  // ============================================================================
  // VIRTUAL SERVICE LOGS - Registros de atendimento virtual
  // ============================================================================

  // IMPORTANT: Specific routes must come BEFORE generic :entityType/:entityId routes
  
  // Get last service log for each entity (batch query)
  app.get('/api/service-logs/last/:entityType', authenticateUser, async (req: any, res) => {
    try {
      const { entityType } = req.params;
      
      const validEntityTypes = ['customer', 'lead'];
      if (!validEntityTypes.includes(entityType)) {
        return res.status(400).json({ message: "Tipo de entidade inválido" });
      }
      
      // Get the last service log for each customer/lead using DISTINCT ON
      const result = await db.execute(sql`
        SELECT DISTINCT ON (customer_id) 
          customer_id, 
          attendance_date, 
          attendant_name,
          service_type
        FROM virtual_service_logs 
        WHERE entity_type = ${entityType}
        ORDER BY customer_id, attendance_date DESC
      `);
      
      // Return as a map for easy lookup
      const lastLogsMap: Record<string, { date: string; attendant: string; serviceType: string }> = {};
      for (const row of result.rows as any[]) {
        lastLogsMap[row.customer_id] = {
          date: row.attendance_date,
          attendant: row.attendant_name,
          serviceType: row.service_type
        };
      }
      
      res.json(lastLogsMap);
    } catch (error) {
      console.error("Error fetching last service logs:", error);
      res.status(500).json({ message: "Falha ao buscar últimos atendimentos" });
    }
  });

  // Get virtual service logs statistics
  app.get('/api/service-logs/stats', authenticateUser, async (req: any, res) => {
    try {
      // Total de atendimentos virtuais
      const totalResult = await db.execute(sql`
        SELECT COUNT(*) as total FROM virtual_service_logs
      `);
      
      // Atendimentos do dia atual
      const todayResult = await db.execute(sql`
        SELECT COUNT(*) as today FROM virtual_service_logs 
        WHERE DATE(attendance_date) = CURRENT_DATE
      `);
      
      // Atendimentos do mês atual
      const monthResult = await db.execute(sql`
        SELECT COUNT(*) as month FROM virtual_service_logs 
        WHERE EXTRACT(MONTH FROM attendance_date) = EXTRACT(MONTH FROM CURRENT_DATE)
        AND EXTRACT(YEAR FROM attendance_date) = EXTRACT(YEAR FROM CURRENT_DATE)
      `);
      
      // Atendimentos por atendente (top 5)
      const byAttendantResult = await db.execute(sql`
        SELECT attendant_name, COUNT(*) as count 
        FROM virtual_service_logs 
        WHERE EXTRACT(MONTH FROM attendance_date) = EXTRACT(MONTH FROM CURRENT_DATE)
        AND EXTRACT(YEAR FROM attendance_date) = EXTRACT(YEAR FROM CURRENT_DATE)
        GROUP BY attendant_name 
        ORDER BY count DESC 
        LIMIT 5
      `);
      
      res.json({
        total: parseInt(totalResult.rows[0]?.total || '0'),
        today: parseInt(todayResult.rows[0]?.today || '0'),
        month: parseInt(monthResult.rows[0]?.month || '0'),
        byAttendant: byAttendantResult.rows || []
      });
    } catch (error) {
      console.error("Error fetching service logs stats:", error);
      res.status(500).json({ message: "Falha ao buscar estatísticas de atendimentos" });
    }
  });

  // Get all service logs for a date range (for Vendas Digitais dashboard)
  app.get('/api/service-logs/all', authenticateUser, async (req: any, res) => {
    try {
      const { startDate, endDate } = req.query;
      
      if (!startDate || !endDate) {
        return res.status(400).json({ message: "startDate e endDate são obrigatórios" });
      }
      
      const result = await db.execute(sql`
        SELECT 
          id,
          customer_id,
          entity_type,
          attendant_id,
          attendant_name,
          attendance_date,
          CASE 
            WHEN service_type IN ('debito_vencido', 'venda', 'prospecao') THEN service_type
            ELSE 'prospecao'
          END as service_type,
          notes,
          images,
          created_at
        FROM virtual_service_logs 
        WHERE attendance_date >= ${startDate}::timestamptz 
        AND attendance_date <= ${endDate}::timestamptz
        ORDER BY attendance_date DESC
      `);
      
      res.json(result.rows || []);
    } catch (error) {
      console.error("Error fetching all service logs:", error);
      res.status(500).json({ message: "Falha ao buscar registros de atendimento" });
    }
  });

