  // Commission dashboard - comprehensive endpoint for the new goals system
  app.get('/api/sales-goals/commission-dashboard', authenticateUser, async (req: any, res) => {
    try {
      const user = req.currentUser;
      const { month, year } = req.query;
      const targetMonth = month ? parseInt(month as string) : getBrazilMonth();
      const targetYear = year ? parseInt(year as string) : getBrazilYear();

      // Commission tier definitions
      const COMMISSION_TIERS: Record<string, { thresholds: number[]; rates: number[] }> = {
        vendedor_clt: {
          thresholds: [0, 85, 100, 110, 120],
          rates: [0.80, 1.50, 2.50, 3.50, 4.50],
        },
        vendedor_pj: {
          thresholds: [0, 85, 100, 110, 120],
          rates: [3.50, 4.50, 6.00, 6.50, 7.50],
        },
        telemarketing: {
          thresholds: [0, 90, 100, 110, 120],
          rates: [1.50, 2.00, 3.00, 3.50, 4.00],
        },
      };

      function getCommissionInfo(sellerType: string, achievementPct: number) {
        const tiers = COMMISSION_TIERS[sellerType];
        if (!tiers) return { tier: 0, rate: 0, tierLabel: 'N/A' };
        let tier = 0;
        for (let i = tiers.thresholds.length - 1; i >= 0; i--) {
          if (achievementPct >= tiers.thresholds[i]) {
            tier = i;
            break;
          }
        }
        const tierLabels = sellerType === 'telemarketing'
          ? ['Até 89,99%', '90% a 99,99%', '100% a 109,99%', '110% a 119,99%', '120% ou mais']
          : ['Até 84,99%', '85% a 99,99%', '100% a 109,99%', '110% a 119,99%', '120% ou mais'];
        return { tier: tier + 1, rate: tiers.rates[tier], tierLabel: tierLabels[tier] };
      }

      // Fetch all active users with relevant roles
      const allUsers = await db.select().from(users).where(eq(users.isActive, true));

      // Fetch goals for the month
      const goals = await storage.getSalesGoals(undefined, targetMonth, targetYear);

      // Working days calculation
      const startDate = new Date(targetYear, targetMonth - 1, 1);
      const endDate = new Date(targetYear, targetMonth, 0);
      const holidays = [
        `${targetYear}-01-01`, `${targetYear}-04-18`, `${targetYear}-04-21`,
        `${targetYear}-05-01`, `${targetYear}-06-19`, `${targetYear}-09-07`,
        `${targetYear}-10-12`, `${targetYear}-11-02`, `${targetYear}-11-15`,
        `${targetYear}-11-20`, `${targetYear}-12-25`,
      ];
      let workingDaysInMonth = 0;
      let workingDaysElapsed = 0;
      const today = new Date();
      for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
        const dow = d.getDay();
        const dateStr = d.toISOString().slice(0, 10);
        if (dow !== 0 && dow !== 6 && !holidays.includes(dateStr)) {
          workingDaysInMonth++;
          if (d <= today) workingDaysElapsed++;
        }
      }
      if (workingDaysElapsed === 0) workingDaysElapsed = 1;

      function getEffectiveSellerType(u: any): string {
        if (u.sellerType && ['vendedor_clt', 'vendedor_pj', 'telemarketing'].includes(u.sellerType)) {
          return u.sellerType;
        }
        if (u.role === 'telemarketing') return 'telemarketing';
        return 'vendedor_pj';
      }

      const goalSellerIds = goals.map((g: any) => g.sellerId).filter((id: string) => id !== 'TELEMARKETING');
      const relevantSellers = allUsers.filter(u =>
        u.isActive && (
          goalSellerIds.includes(u.id) ||
          (u.role === 'vendedor' && u.omieVendorCode) ||
          (u.sellerType && ['vendedor_clt', 'vendedor_pj'].includes(u.sellerType)) ||
          u.role === 'telemarketing' ||
          u.sellerType === 'telemarketing'
        )
      );

      // All sellers (including telemarketing) are processed individually
      const individualSellers = relevantSellers;

      const results: any[] = [];

      // Faturamento realizado a partir de billing_pipeline (billings/Omie descontinuado)
      const pipelineRevenueResult: any = await db.execute(sql`
        SELECT seller_id, omie_instance_id, COALESCE(SUM(sale_value), 0) AS total
        FROM billing_pipeline
        WHERE created_at >= ${startDate} AND created_at < (${startDate}::timestamptz + interval '1 month')
        GROUP BY seller_id, omie_instance_id
      `);
      const pipelineRevenueBySeller = new Map<string, number>();
      const pipelineInstanceBySeller = new Map<string, Record<string, number>>();
      for (const _r of (pipelineRevenueResult.rows || [])) {
        const _sid = String((_r as any).seller_id);
        const _val = Number((_r as any).total) || 0;
        pipelineRevenueBySeller.set(_sid, (pipelineRevenueBySeller.get(_sid) || 0) + _val);
        const _inst = (_r as any).omie_instance_id;
        if (_inst) {
          const _m = pipelineInstanceBySeller.get(_sid) || {};
          _m[String(_inst)] = (_m[String(_inst)] || 0) + _val;
          pipelineInstanceBySeller.set(_sid, _m);
        }
      }
      const _sellerKeys = (u: any) => new Set([String(u.id), String(u.omieVendorCode || ''), 'omie-vendor-' + String(u.omieVendorCode || '')]);
      const pipelineRevenueForSeller = (u: any): number => {
        const keys = _sellerKeys(u); let t = 0;
        for (const [k, v] of pipelineRevenueBySeller) { if (keys.has(k)) t += v; }
        return t;
      };
      const pipelineRevByInstanceForSeller = (u: any): Record<string, number> => {
        const keys = _sellerKeys(u); const out: Record<string, number> = {};
        for (const [k, m] of pipelineInstanceBySeller) { if (keys.has(k)) { for (const i of Object.keys(m)) { out[i] = (out[i] || 0) + m[i]; } } }
        return out;
      };
      for (const seller of individualSellers) {
        try {
          const effectiveType = getEffectiveSellerType(seller);
          const goal = goals.find((g: any) => g.sellerId === seller.id);
          const revenueGoal = goal ? parseFloat(goal.revenueGoal || '0') : 0;

          const metrics = await storage.getSalesMetrics(seller.id, targetMonth, targetYear);
          const totalRevenue = pipelineRevenueForSeller(seller);
          const projection = workingDaysElapsed > 0
            ? (totalRevenue / workingDaysElapsed) * workingDaysInMonth
            : 0;
          const achievementPct = revenueGoal > 0 ? (projection / revenueGoal) * 100 : 0;
          const commission = getCommissionInfo(effectiveType, achievementPct);

          results.push({
            sellerId: seller.id,
            sellerName: `${seller.firstName || ''} ${seller.lastName || ''}`.trim(),
            sellerType: effectiveType,
            revenueGoal,
            revenueActual: totalRevenue,
            revenueByInstance: pipelineRevByInstanceForSeller(seller),
            revenueProjected: projection,
            achievementPct: Math.round(achievementPct * 100) / 100,
            commissionRate: commission.rate,
            commissionTier: commission.tier,
            commissionTierLabel: commission.tierLabel,
          });
        } catch (sellerError: any) {
          console.error(`⚠️ [COMMISSION] Error processing seller ${seller.id}:`, sellerError.message);
          results.push({
            sellerId: seller.id,
            sellerName: `${seller.firstName || ''} ${seller.lastName || ''}`.trim(),
            sellerType: getEffectiveSellerType(seller),
            revenueGoal: 0,
            revenueActual: 0,
            revenueByInstance: {},
            revenueProjected: 0,
            achievementPct: 0,
            commissionRate: 0,
            commissionTier: 0,
            commissionTierLabel: 'Erro',
          });
        }
      }

      // Telemarketing is now processed individually (each user has their own row in results[])
      // Keep telemarketingResult as null — no more collective aggregation
      const telemarketingResult: any = null;

      // Save/update history
      const allResults = [...results, ...(telemarketingResult ? [telemarketingResult] : [])];
      for (const r of allResults) {
        try {
          await db.execute(sql`
            INSERT INTO sales_goal_history (id, seller_id, seller_type, month, year, revenue_goal, revenue_actual, revenue_projected, achievement_pct, commission_pct, commission_tier, working_days_total, working_days_elapsed, is_projected, updated_at)
            VALUES (gen_random_uuid(), ${r.sellerId}, ${r.sellerType}, ${targetMonth}, ${targetYear}, ${r.revenueGoal}, ${r.revenueActual}, ${r.revenueProjected}, ${r.achievementPct}, ${r.commissionRate}, ${r.commissionTier}, ${workingDaysInMonth}, ${workingDaysElapsed}, ${workingDaysElapsed < workingDaysInMonth}, NOW())
            ON CONFLICT (seller_id, month, year)
            DO UPDATE SET revenue_actual = EXCLUDED.revenue_actual, revenue_projected = EXCLUDED.revenue_projected, achievement_pct = EXCLUDED.achievement_pct, commission_pct = EXCLUDED.commission_pct, commission_tier = EXCLUDED.commission_tier, working_days_total = EXCLUDED.working_days_total, working_days_elapsed = EXCLUDED.working_days_elapsed, is_projected = EXCLUDED.is_projected, updated_at = NOW()
          `);
        } catch (e) {
          // ignore upsert errors
        }
      }

      let historyRows: any = { rows: [] };
      if (allResults.length > 0) {
        try {
          const sellerIds = allResults.map(r => r.sellerId);
          const sellerIdConditions = sql.join(sellerIds.map(id => sql`${id}`), sql`, `);
          historyRows = await db.execute(sql`
            SELECT * FROM sales_goal_history
            WHERE seller_id IN (${sellerIdConditions})
            ORDER BY year DESC, month DESC
            LIMIT 120
          `);
        } catch (histErr: any) {
          console.error('⚠️ [COMMISSION] Error fetching history:', histErr.message);
        }
      }

      const instancesResult = await db.execute(sql`SELECT id, name, display_name FROM omie_instances WHERE is_active = true`);
      const instanceLabels: Record<string, string> = {};
      for (const inst of instancesResult.rows as any[]) {
        instanceLabels[inst.id] = inst.name || inst.display_name || inst.id;
      }

      res.json({
        month: targetMonth,
        year: targetYear,
        workingDaysInMonth,
        workingDaysElapsed,
        commissionTiers: COMMISSION_TIERS,
        sellers: results,
        telemarketing: telemarketingResult,
        history: historyRows.rows || [],
        currentUserId: user.id,
        instanceLabels,
      });
    } catch (error: any) {
      console.error("Error fetching commission dashboard:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Yearly summary - goals and execution for the entire year
  app.get('/api/sales-goals/yearly-summary', authenticateUser, async (req: any, res) => {
    try {
      const user = req.currentUser;
      if (!['admin', 'coordinator', 'administrative'].includes(user.role)) {
        return res.status(403).json({ message: "Access denied" });
      }
      const targetYear = parseInt(req.query.year as string) || new Date().getFullYear();

      const allGoals = await db.select().from(salesGoals).where(eq(salesGoals.year, targetYear));

      const sellerMap: Record<string, { sellerId: string, sellerName: string, months: Record<number, { goal: number, actual: number }> }> = {};

      const allUsersData = await db.select().from(users).where(eq(users.isActive, true));

      for (const goal of allGoals) {
        if (!sellerMap[goal.sellerId]) {
          let name = goal.sellerId;
          if (goal.sellerId === 'TELEMARKETING') {
            name = 'Vendas Internas (Telemarketing)';
          } else {
            const u = allUsersData.find(u => u.id === goal.sellerId);
            if (u) name = `${u.firstName || ''} ${u.lastName || ''}`.trim();
          }
          sellerMap[goal.sellerId] = { sellerId: goal.sellerId, sellerName: name, months: {} };
        }
        sellerMap[goal.sellerId].months[goal.month] = {
          goal: parseFloat(goal.revenueGoal?.toString() || '0'),
          actual: 0,
        };
      }

      const historyRows = await db.execute(sql`
        SELECT seller_id, month, revenue_actual 
        FROM sales_goal_history 
        WHERE year = ${targetYear}
      `);

      for (const row of (historyRows.rows || [])) {
        const sid = row.seller_id as string;
        const month = row.month as number;
        if (sellerMap[sid] && sellerMap[sid].months[month] !== undefined) {
          sellerMap[sid].months[month].actual = parseFloat((row.revenue_actual as string) || '0');
        } else if (sellerMap[sid]) {
          sellerMap[sid].months[month] = { goal: 0, actual: parseFloat((row.revenue_actual as string) || '0') };
        }
      }

      const summary = Object.values(sellerMap).map(s => {
        let totalGoal = 0;
        let totalActual = 0;
        for (const m of Object.values(s.months)) {
          totalGoal += m.goal;
          totalActual += m.actual;
        }
        return { ...s, totalGoal, totalActual };
      });

      res.json({ year: targetYear, sellers: summary });
    } catch (error: any) {
      console.error("Error fetching yearly summary:", error);
      res.status(500).json({ message: error.message });
    }
  });

