  // Rota para buscar débitos salvos no banco (carregamento rápido)
  app.get('/api/omie/overdue-debts/cached', authenticateUser, async (req: any, res) => {
    try {
      console.log(`[OVERDUE-DEBTS-CACHED] Request from user: ${req.currentUser?.email}, ID: ${req.currentUser?.id}`);
      const savedDebts = await storage.getOverdueDebts();
      console.log(`[OVERDUE-DEBTS-CACHED] Found ${savedDebts?.length || 0} debts in database`);
      
      if (!savedDebts || savedDebts.length === 0) {
        return res.json({
          debts: [],
          totalAmount: 0,
          totalClients: 0,
          message: "Nenhum débito salvo. Execute a sincronização."
        });
      }

      // Buscar todos os clientes para mapear telefones e vendedores
      const allCustomers = await storage.getAllCustomers();
      const customerDataMap = new Map<string, { phone?: string; sellerId?: string }>();
      
      // Buscar todos os usuários para mapear sellerId -> omieVendorCode
      const allUsers = await storage.getUsers();
      const userVendorCodeMap = new Map<string, string>();
      allUsers.forEach((user: any) => {
        if (user.id && user.omieVendorCode) {
          userVendorCodeMap.set(user.id, user.omieVendorCode);
        }
      });
      
      allCustomers.forEach(customer => {
        if (customer.omieClientCode) {
          // Obter código do vendedor do Omie via sellerId do cliente
          let vendorCode = '';
          if (customer.sellerId && userVendorCodeMap.has(customer.sellerId)) {
            vendorCode = userVendorCodeMap.get(customer.sellerId) || '';
          }
          
          // Filtrar telefones inválidos/placeholder
          const validPhone = customer.phone && 
            customer.phone !== '(00) 00000-0000' && 
            !customer.phone.includes('00000-0000') 
              ? customer.phone 
              : '';
          
          customerDataMap.set(customer.omieClientCode, {
            phone: validPhone,
            sellerId: vendorCode
          });
        }
      });

      // Transformar dados do banco para o formato esperado pelo frontend
      // Cada linha já representa UM cliente com TODOS os seus débitos
      const debts = savedDebts.map(debt => {
        const customerData = customerDataMap.get(debt.omieClientId);
        
        // Se não temos vendedores dos títulos, usar o vendedor do cliente
        let vendedoresFinais = debt.vendedores || [];
        if (vendedoresFinais.length === 0 && customerData?.sellerId) {
          const vendorCode = parseInt(customerData.sellerId);
          if (!isNaN(vendorCode)) {
            vendedoresFinais = [vendorCode];
          }
        }
        
        return {
          cliente: {
            codigo_cliente_omie: parseInt(debt.omieClientId),
            nome_fantasia: debt.clientName,
            cnpj_cpf: debt.clientDocument || '',
            telefone: customerData?.phone || ''
          },
          debitos: debt.debts || [],
          valorTotal: parseFloat(debt.totalAmount),
          diasMaximoAtraso: debt.maxDaysOverdue,
          vendedores: vendedoresFinais,
          omieInstanceId: debt.omieInstanceId || null // Tag multi-tenant
        };
      });

      const totalAmount = debts.reduce((sum, d) => sum + d.valorTotal, 0);

      // Obter data da última sincronização (usar a mais recente dos débitos)
      const lastSyncAt = savedDebts.length > 0 && savedDebts[0].lastSyncAt 
        ? savedDebts[0].lastSyncAt 
        : null;

      res.json({
        debts,
        totalAmount,
        totalClients: debts.length,
        lastSyncAt
      });
    } catch (error) {
      console.error("Error fetching cached overdue debts:", error);
      console.error("Error stack:", error instanceof Error ? error.stack : 'No stack trace');
      res.status(500).json({ 
        message: "Erro ao buscar débitos salvos: " + (error instanceof Error ? error.message : 'Erro desconhecido'),
        debts: [],
        totalAmount: 0,
        totalClients: 0
      });
    }
  });

  // Rota para sincronizar débitos do Omie (operação demorada) - Apenas usuários administrativos
  app.get('/api/omie/overdue-debts', authenticateUser, async (req: any, res) => {
    try {
      // Verificar se usuário tem permissão para sincronizar (admin, coordinator, administrative)
      const userRole = req.currentUser?.role;
      console.log(`[OVERDUE-DEBTS] Sync request - User: ${req.currentUser?.email}, Role: ${userRole}, ID: ${req.currentUser?.id}`);
      if (!userRole || !['admin', 'coordinator', 'administrative'].includes(userRole)) {
        console.log(`[OVERDUE-DEBTS] Access denied for role: ${userRole}`);
        return res.status(403).json({ 
          message: "Apenas usuários administrativos podem sincronizar débitos" 
        });
      }

      // Evitar cache
      res.set({
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        'Pragma': 'no-cache',
        'Expires': '0'
      });

      const timestamp = new Date().toISOString();
      console.log(`[${timestamp}] Fetching overdue debts from ALL Omie instances - NO CACHE...`);

      // Aumentar timeout para sincronizações longas (10 minutos)
      req.setTimeout(600000);
      res.setTimeout(600000);

      // Multi-tenant: iterar todas as instâncias ativas + instância padrão (env vars)
      const allInstances = (await storage.getOmieInstances()).filter((i: any) => i.isActive);
      const debtSvcs: Array<{ svc: OmieService; name: string }> = [];
      
      // Adicionar instâncias registradas no banco
      for (const inst of allInstances) {
        debtSvcs.push({ svc: OmieService.createFromInstance(inst, storage), name: inst.displayName || inst.name });
      }
      
      // Adicionar instância padrão (env vars) se não coincide com nenhuma instância registrada
      const defaultSvc = getOmieService(storage);
      if (defaultSvc) {
        const envKey = process.env.OMIE_APP_KEY;
        const alreadyIncluded = allInstances.some((i: any) => i.appKey === envKey);
        if (!alreadyIncluded) {
          debtSvcs.push({ svc: defaultSvc, name: 'BSB (env vars)' });
        }
      }
      
      if (debtSvcs.length === 0) {
        return res.status(503).json({ message: "Integração Omie não configurada" });
      }

      console.log(`📡 [OVERDUE-DEBTS] Sincronizando ${debtSvcs.length} instâncias EM PARALELO: ${debtSvcs.map(d => d.name).join(', ')}`);

      let allDebts: any[] = [];
      let totalClients = 0;
      let totalAmount = 0;
      const instanceErrors: string[] = [];

      // Executar TODAS as instâncias em paralelo para evitar timeout
      const results = await Promise.allSettled(
        debtSvcs.map(async ({ svc, name }) => {
          console.log(`📡 [OVERDUE-DEBTS] Iniciando sync instância: ${name}`);
          const overdueData = await svc.getOverdueDebts();
          return { svc, name, overdueData };
        })
      );

      // Processar resultados
      for (const result of results) {
        if (result.status === 'fulfilled') {
          const { svc, name, overdueData } = result.value;
          if (overdueData.success) {
            await storage.syncOverdueDebts(overdueData.debts, false, svc.omieInstanceId);
            allDebts = allDebts.concat(overdueData.debts || []);
            totalClients += overdueData.totalClients || 0;
            totalAmount += overdueData.totalAmount || 0;
            console.log(`✅ [OVERDUE-DEBTS] Instância ${name}: ${overdueData.debts?.length || 0} clientes com débitos`);
          } else {
            console.error(`❌ [OVERDUE-DEBTS] Instância ${name} falhou: ${overdueData.errorMessage}`);
            instanceErrors.push(`${name}: ${overdueData.errorMessage}`);
          }
        } else {
          const error = result.reason;
          const name = 'instância desconhecida';
          console.error(`❌ [OVERDUE-DEBTS] Erro em instância:`, error?.message || error);
          instanceErrors.push(`${name}: ${error?.message || 'Erro desconhecido'}`);
        }
      }

      console.log(`[${timestamp}] Overdue debts fetch complete - ${totalClients} clients from ${debtSvcs.length} instances (${instanceErrors.length} erros)`);
      
      // Gerar e salvar planilha Excel automaticamente após a sincronização
      try {
        const fileName = `debitos-vencidos-${getBrazilDateString()}.xlsx`;
        
        const detalhesData: any[] = [];
        allDebts.forEach((debt: any) => {
          (debt.debitos || []).forEach((documento: any) => {
            detalhesData.push({
              'Cliente': debt.cliente.nome_fantasia,
              'CNPJ/CPF': debt.cliente.cnpj_cpf,
              'Nº Nota Fiscal': documento.numero_documento_fiscal || documento.numero_documento || 'N/A',
              'Valor': documento.valor,
              'Data Vencimento': documento.data_vencimento,
              'Dias Atraso': documento.dias_atraso,
            });
          });
        });

        const wb = XLSX.utils.book_new();
        const ws = XLSX.utils.json_to_sheet(detalhesData);
        XLSX.utils.book_append_sheet(wb, ws, 'Detalhes dos Documentos');

        const excelBuffer = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' });
        const base64Data = excelBuffer.toString('base64');

        await storage.saveExportedReport(
          'overdue_debts',
          fileName,
          base64Data,
          {
            totalClients: totalClients,
            totalAmount: totalAmount,
            syncDate: nowBrazil().toISOString()
          },
          req.user?.id
        );

        console.log(`[${timestamp}] Excel report saved successfully: ${fileName}`);
      } catch (excelError) {
        console.error('Error generating/saving Excel report:', excelError);
      }
      
      res.json({
        success: true,
        debts: allDebts,
        totalClients,
        totalAmount,
        instanceErrors: instanceErrors.length > 0 ? instanceErrors : undefined
      });

    } catch (error) {
      console.error("Error fetching overdue debts from Omie:", error);
      res.status(500).json({ 
        message: "Erro ao buscar débitos em atraso no Omie",
        error: error instanceof Error ? error.message : 'Erro desconhecido'
      });
    }
  });

