  // Planejar rotas de entrega para múltiplos veículos
  app.post("/api/delivery-routes/plan", authenticateUser, requireRole(['admin', 'coordinator', 'administrative']), async (req: any, res) => {
    try {
      const { orderIds, vehicles, routeDate } = req.body;

      if (!orderIds || !Array.isArray(orderIds) || orderIds.length === 0) {
        return res.status(400).json({ message: "Order IDs are required" });
      }

      if (!vehicles || !Array.isArray(vehicles) || vehicles.length === 0) {
        return res.status(400).json({ message: "Vehicle configurations are required" });
      }

      // Buscar billings selecionados para roteirização
      // Como /api/deliveries retorna billing.id (não sales_card.id), 
      // precisamos buscar os billings e criar sales_cards temporários
      const billingsResult = await db.execute<{
        id: string;
        invoiceNumber: string;
        omieOrderId: string;
        orderNumber: string;
        customerId: string;
        customerName: string;
        customerAddress: string;
        customerLatitude: string;
        customerLongitude: string;
        deliveryWeekdays: any;
        deliveryTimeSlots: any;
        deliverySaturdayTimeSlots: any;
        exclusiveVehicle: boolean;
        vehicleTypes: any;
        averageDeliveryTime: number;
        isUrgent: boolean;
        saleValue: number;
        products: any;
        scheduledDate: Date;
        paymentMethod: string;
        operationType: string;
      }>(sql`
        SELECT DISTINCT ON (bp.id)
          bp.id,
          bp.invoice_number as "invoiceNumber",
          NULL as "omieOrderId",
          bp.order_number as "orderNumber",
          COALESCE(c.id, 'billing-' || bp.id) as "customerId",
          COALESCE(c.fantasy_name, bp.customer_name) as "customerName",
          COALESCE(c.address, '') as "customerAddress",
          c.latitude as "customerLatitude",
          c.longitude as "customerLongitude",
          c.delivery_weekdays as "deliveryWeekdays",
          c.delivery_time_slots as "deliveryTimeSlots",
          c.delivery_saturday_time_slots as "deliverySaturdayTimeSlots",
          c.exclusive_vehicle as "exclusiveVehicle",
          c.vehicle_types as "vehicleTypes",
          COALESCE(c.average_delivery_time, 30) as "averageDeliveryTime",
          false as "isUrgent",
          bp.sale_value as "saleValue",
          bp.products,
          bp.created_at as "scheduledDate",
          bp.payment_method as "paymentMethod",
          bp.operation_type as "operationType"
        FROM billing_pipeline bp
        LEFT JOIN customers c ON c.id = bp.customer_id
        WHERE bp.id = ANY(ARRAY[${sql.join(orderIds.map((id: string) => sql`${id}`), sql`, `)}])
        ORDER BY bp.id, bp.created_at
      `);
      
      const orders = billingsResult.rows;
      
      console.log(`📦 [ROUTE-PLANNING] Recebidos ${orderIds.length} billing IDs, encontrados ${orders.length} billings válidos`);

      if (orders.length === 0) {
        return res.status(400).json({ 
          message: "Nenhum pedido válido encontrado para os IDs fornecidos",
          requestedIds: orderIds,
          foundCount: 0
        });
      }

      // Validar que todos os pedidos têm coordenadas válidas
      console.log(`🔍 [ROUTE-PLANNING] Validando coordenadas de ${orders.length} pedidos...`);
      const invalidOrders = orders.filter(o => {
        let lat = o.customerLatitude;
        let lng = o.customerLongitude;
        
        console.log(`  → ${o.customerName}: lat=${lat} (type: ${typeof lat}), lng=${lng} (type: ${typeof lng})`);
        
        // Verificar se é null, undefined, string vazia
        if (lat === null || lat === undefined || lng === null || lng === undefined) {
          console.log(`    ❌ Coordenadas null/undefined`);
          return true;
        }
        
        // Se for string, fazer trim
        if (typeof lat === 'string') {
          lat = lat.trim();
        }
        if (typeof lng === 'string') {
          lng = lng.trim();
        }
        
        // Verificar strings vazias ou inválidas
        if (lat === '' || lng === '' || lat === 'NaN' || lng === 'NaN' || lat === 'Infinity' || lng === 'Infinity' || lat === '-Infinity' || lng === '-Infinity') {
          console.log(`    ❌ Coordenadas vazias ou inválidas: lat="${lat}", lng="${lng}"`);
          return true;
        }
        
        // Converter para número e validar
        const latNum = typeof lat === 'number' ? lat : parseFloat(lat as string);
        const lngNum = typeof lng === 'number' ? lng : parseFloat(lng as string);
        
        // Verificar se é número válido
        if (isNaN(latNum) || isNaN(lngNum) || !isFinite(latNum) || !isFinite(lngNum)) {
          console.log(`    ❌ Não é número finito: latNum=${latNum}, lngNum=${lngNum}`);
          return true;
        }
        
        // Verificar se é zero (coordenada inválida)
        if (latNum === 0 || lngNum === 0) {
          console.log(`    ❌ Coordenadas zero: latNum=${latNum}, lngNum=${lngNum}`);
          return true;
        }
        
        // Verificar ranges geográficos válidos
        if (Math.abs(latNum) > 90 || Math.abs(lngNum) > 180) {
          console.log(`    ❌ Fora do range geográfico: latNum=${latNum}, lngNum=${lngNum}`);
          return true;
        }
        
        console.log(`    ✅ Coordenadas válidas: lat=${latNum}, lng=${lngNum}`);
        return false;
      });
      
      if (invalidOrders.length > 0) {
        console.warn(`⚠️ [ROUTE-PLANNING] ${invalidOrders.length} pedidos sem coordenadas válidas:`, 
                     invalidOrders.map(o => ({ id: o.id, name: o.customerName, lat: o.customerLatitude, lng: o.customerLongitude })));
        
        // Retornar status 422 com detalhes dos clientes para modal de correção
        return res.status(422).json({ 
          code: 'MISSING_COORDINATES',
          message: `${invalidOrders.length} ${invalidOrders.length === 1 ? 'pedido não possui' : 'pedidos não possuem'} coordenadas de cliente cadastradas.`,
          missingCoordinates: invalidOrders.map(o => ({ 
            billingId: o.id,
            customerId: o.customerId,
            customerName: o.customerName, 
            address: o.customerAddress,
            latitude: o.customerLatitude || '',
            longitude: o.customerLongitude || ''
          }))
        });
      }

      // Converter billings para formato do serviço de roteirização
      const deliveryOrders = orders.map(o => {
        const lat = parseFloat(o.customerLatitude as string);
        const lng = parseFloat(o.customerLongitude as string);
        
        // Parse JSON fields
        const deliveryWeekdays = typeof o.deliveryWeekdays === 'string' 
          ? JSON.parse(o.deliveryWeekdays) 
          : (Array.isArray(o.deliveryWeekdays) ? o.deliveryWeekdays : null);
        
        const deliveryTimeSlots = typeof o.deliveryTimeSlots === 'string'
          ? JSON.parse(o.deliveryTimeSlots)
          : (Array.isArray(o.deliveryTimeSlots) ? o.deliveryTimeSlots : []);
        
        const vehicleTypes = typeof o.vehicleTypes === 'string'
          ? JSON.parse(o.vehicleTypes)
          : (Array.isArray(o.vehicleTypes) ? o.vehicleTypes : []);
        
        console.log(`📍 [CONVERSION] ${o.customerName}:`, {
          lat, lng,
          deliveryWeekdays,
          deliveryTimeSlots,
          exclusiveVehicle: o.exclusiveVehicle,
          vehicleTypes
        });
        
        return {
          id: o.id,
          customerId: o.customerId,
          customerName: o.customerName,
          customerAddress: o.customerAddress,
          customerLatitude: lat,
          customerLongitude: lng,
          averageDeliveryTime: o.averageDeliveryTime || 30,
          exclusiveVehicle: o.exclusiveVehicle || false,
          vehicleTypes: vehicleTypes,
          isUrgent: o.isUrgent || false,
          saleValue: parseFloat((o.saleValue as any) || 0),
          products: o.products,
          scheduledDate: o.scheduledDate || null,
          completedDate: o.scheduledDate || null,
          paymentMethod: o.paymentMethod || null,
          operationType: o.operationType || null,
          customerWeekdays: deliveryWeekdays, // Dias de ENTREGA permitidos
          deliveryTimeSlots: deliveryTimeSlots, // Horários de ENTREGA permitidos
        };
      });
      
      console.log(`✅ [ROUTE-PLANNING] ${deliveryOrders.length} pedidos prontos para roteirização`);

      // Planejar rotas
      const { planDeliveryRoutes } = await import('./deliveryRouteService');
      const plan = await planDeliveryRoutes(
        storage,
        deliveryOrders,
        vehicles,
        routeDate ? new Date(routeDate) : nowBrazil()
      );

      res.json(plan);
    } catch (error: any) {
      console.error("Error planning delivery routes:", error);
      res.status(500).json({ message: "Failed to plan delivery routes", error: error.message });
    }
  });


  // Salvar rotas planejadas
  app.post("/api/delivery-routes/save", authenticateUser, requireRole(['admin', 'coordinator', 'administrative']), async (req: any, res) => {
    try {
      const { routes } = req.body;

      if (!routes || !Array.isArray(routes) || routes.length === 0) {
        return res.status(400).json({ message: "Routes are required" });
      }

      console.log(`💾 [SAVE-ROUTES] ========== INÍCIO DO SALVAMENTO ==========`);
      console.log(`💾 [SAVE-ROUTES] Timestamp: ${new Date().toISOString()}`);
      console.log(`💾 [SAVE-ROUTES] Salvando ${routes.length} rotas planejadas`);
      console.log(`💾 [SAVE-ROUTES] Primeira rota routeDate recebido:`, routes[0]?.route?.routeDate);
      console.log(`💾 [SAVE-ROUTES] Tipo do routeDate:`, typeof routes[0]?.route?.routeDate);
      console.log(`💾 [SAVE-ROUTES] Driver ID:`, routes[0]?.route?.driverId);
      console.log(`💾 [SAVE-ROUTES] Driver Name:`, routes[0]?.route?.driverName);
      console.log(`💾 [SAVE-ROUTES] Total stops:`, routes[0]?.stops?.length);
      console.log(`💾 [SAVE-ROUTES] Request body completo:`, JSON.stringify(routes[0]?.route, null, 2));

      // Validar todos os driverIds ANTES do loop
      for (const routePlan of routes) {
        if (!routePlan.route?.driverId || routePlan.route.driverId.trim() === '') {
          console.error('❌ [SAVE-ROUTES] driverId é obrigatório para todas as rotas');
          return res.status(400).json({ message: "Driver ID is required for all routes" });
        }
        
        if (!routePlan.route?.routeDate) {
          console.error('❌ [SAVE-ROUTES] routeDate é obrigatório:', routePlan.route?.routeDate);
          return res.status(400).json({ message: "Route date is required for all routes" });
        }
        
        // Validar campos numéricos obrigatórios
        const route = routePlan.route;
        if (isNaN(parseFloat(route.startLatitude)) || isNaN(parseFloat(route.startLongitude))) {
          return res.status(400).json({ message: "Invalid coordinates for route start location" });
        }
        if (isNaN(parseFloat(route.totalDistance)) || parseFloat(route.totalDistance) < 0) {
          return res.status(400).json({ message: "Invalid total distance" });
        }
        if (isNaN(parseInt(route.totalDuration)) || parseInt(route.totalDuration) < 0) {
          return res.status(400).json({ message: "Invalid total duration" });
        }
        
        // Validar paradas (se houver)
        if (Array.isArray(routePlan.stops) && routePlan.stops.length > 0) {
          for (const stop of routePlan.stops) {
            if (isNaN(parseFloat(stop.latitude)) || isNaN(parseFloat(stop.longitude))) {
              return res.status(400).json({ message: `Invalid coordinates for stop: ${stop.customerName}` });
            }
            if (!stop.billingId) {
              console.warn(`⚠️ [SAVE-ROUTES] Stop ${stop.customerName} missing billingId`);
            }
          }
        }
      }

      const savedRoutes = [];
      const allBillingIds: string[] = [];

      for (const routePlan of routes) {
        const { route, stops } = routePlan;

        // ✅ VALIDAÇÃO: Impedir salvamento de rotas sem paradas
        if (!stops || !Array.isArray(stops) || stops.length === 0) {
          console.warn(`⚠️ [SAVE-ROUTES] Rota do motorista ${route.driverName} ignorada - sem paradas`);
          continue; // Pular esta rota e continuar com as próximas
        }

        // Garantir que routeDate é sempre uma string YYYY-MM-DD
        let dateStr: string;
        if (typeof route.routeDate === 'string') {
          dateStr = route.routeDate;
          // Validar formato YYYY-MM-DD
          if (!/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
            console.error(`❌ [SAVE-ROUTES] Formato de data inválido: ${dateStr}`);
            const d = new Date(route.routeDate);
            dateStr = d.toISOString().split('T')[0];
          }
        } else if (route.routeDate instanceof Date) {
          dateStr = route.routeDate.toISOString().split('T')[0];
        } else {
          const d = new Date(route.routeDate);
          dateStr = d.toISOString().split('T')[0];
        }
        
        const driverName = route.driverName.toUpperCase().replace(/\s+/g, '-');
        
        console.log(`📝 [SAVE-ROUTES] Processando rota com data: ${dateStr}, driverId: ${route.driverId}, data bruta: ${route.routeDate}`);
        
        // ✅ CORRIGIDO: Buscar rotas existentes para este motorista nesta data (qualquer status ativo)
        const existingRoutes = await db.select().from(deliveryRoutes)
          .where(and(
            eq(deliveryRoutes.driverId, route.driverId),
            sql`${deliveryRoutes.routeDate}::text = ${dateStr}`,
            sql`${deliveryRoutes.status} NOT IN ('cancelled', 'concluida', 'cancelada')`
          ));
        
        console.log(`🔍 [SAVE-ROUTES] Encontradas ${existingRoutes.length} rotas ativas para motorista ${route.driverId} em ${dateStr}`);
        
        let savedRoute: any;
        let savedStops: any[];
        
        if (existingRoutes.length > 0) {
          // ✅ ATUALIZAR rota existente (usar a primeira)
          const routeToUpdate = existingRoutes[0];
          console.log(`♻️ [SAVE-ROUTES] Atualizando rota planejada existente: ${routeToUpdate.id} (${routeToUpdate.routeName})`);
          
          // Deletar paradas antigas
          await db.delete(deliveryRouteStops)
            .where(eq(deliveryRouteStops.routeId, routeToUpdate.id));
          console.log(`🗑️ [SAVE-ROUTES] Paradas antigas removidas`);
          
          // Preparar dados das paradas novas
          const stopsData = stops.map((stop: any, index: number) => ({
            routeId: routeToUpdate.id,
            salesCardId: stop.salesCardId,
            billingId: stop.billingId || null,
            customerId: stop.customerId,
            customerName: stop.customerName,
            customerAddress: stop.customerAddress,
            customerLatitude: parseFloat(stop.latitude) || 0,
            customerLongitude: parseFloat(stop.longitude) || 0,
            stopOrder: index + 1,
            estimatedArrival: stop.estimatedArrival || null,  // Keep as string or null - don't convert
            estimatedDeparture: stop.estimatedDeparture || null, // Keep as string or null - don't convert
            estimatedServiceTime: parseInt(stop.estimatedServiceTime) || 30,
            distanceFromPrevious: parseFloat(stop.distanceFromPrevious) || 0,
            isPriority: stop.isUrgent || false,
            status: 'pendente'
          }));
          
          // Inserir paradas novas
          savedStops = await db.insert(deliveryRouteStops).values(stopsData).returning();
          
          // Buscar email do driver para atualizar (normalizado para lowercase)
          let driver = await db.select().from(deliveryDrivers)
            .where(eq(deliveryDrivers.id, route.driverId))
            .limit(1);
          
          // Se não encontrou pelo ID, tentar pelo nome
          if (driver.length === 0 && route.driverName) {
            console.log(`⚠️ [SAVE-ROUTES] Driver não encontrado por ID, buscando por nome: "${route.driverName}"`);
            driver = await db.select().from(deliveryDrivers)
              .where(sql`LOWER(${deliveryDrivers.name}) = LOWER(${route.driverName})`)
              .limit(1);
          }
          
          let driverEmail = driver.length > 0 ? (driver[0].email || '').toLowerCase().trim() : '';
          
          // Se ainda não encontrou email, tentar construir a partir do nome
          if (!driverEmail && route.driverName) {
            const normalizedName = route.driverName.toLowerCase().trim().replace(/\s+/g, '');
            driverEmail = `${normalizedName}@bebahonest.com.br`;
            console.log(`⚠️ [SAVE-ROUTES] Email do driver não encontrado, usando fallback: "${driverEmail}"`);
          }
          
          console.log(`📧 [SAVE-ROUTES] Email do motorista: "${driverEmail}" (id: ${route.driverId})`);
          
          // Atualizar apenas dados da rota
          const [updatedRoute] = await db.update(deliveryRoutes)
            .set({
              driverEmail: driverEmail,
              totalDistance: parseFloat(route.totalDistance) || 0,
              totalDeliveries: stops.length,
              totalDuration: parseInt(route.totalDuration) || 0,
              status: 'rota_enviada', // Enviada automaticamente para o motorista
              sentToDriverAt: nowBrazil(),
              updatedAt: nowBrazil()
            })
            .where(eq(deliveryRoutes.id, routeToUpdate.id))
            .returning();
          
          savedRoute = updatedRoute;
          console.log(`✅ [SAVE-ROUTES] Rota ${routeToUpdate.routeName} atualizada com ${savedStops.length} paradas`);
        } else {
          // ✅ CRIAR nova rota (primeira vez)
          const routeNumber = 1;
          const routeName = `ROTA-${dateStr}-${driverName}-${routeNumber}`;
          
          console.log(`🆕 [SAVE-ROUTES] Criando nova rota: ${routeName}`);
          
          // Buscar email do driver (normalizado para lowercase)
          let driver = await db.select().from(deliveryDrivers)
            .where(eq(deliveryDrivers.id, route.driverId))
            .limit(1);
          
          // Se não encontrou pelo ID, tentar pelo nome
          if (driver.length === 0 && route.driverName) {
            console.log(`⚠️ [SAVE-ROUTES] Driver não encontrado por ID, buscando por nome: "${route.driverName}"`);
            driver = await db.select().from(deliveryDrivers)
              .where(sql`LOWER(${deliveryDrivers.name}) = LOWER(${route.driverName})`)
              .limit(1);
          }
          
          let driverEmail = driver.length > 0 ? (driver[0].email || '').toLowerCase().trim() : '';
          
          // Se ainda não encontrou email, tentar construir a partir do nome
          if (!driverEmail && route.driverName) {
            const normalizedName = route.driverName.toLowerCase().trim().replace(/\s+/g, '');
            driverEmail = `${normalizedName}@bebahonest.com.br`;
            console.log(`⚠️ [SAVE-ROUTES] Email do driver não encontrado, usando fallback: "${driverEmail}"`);
          }
          
          console.log(`📧 [SAVE-ROUTES] Email do motorista: "${driverEmail}" (id: ${route.driverId})`);
          
          const routeData = {
            routeName,
            routeDate: dateStr, // String YYYY-MM-DD
            driverId: route.driverId,
            driverName: route.driverName,
            driverEmail: driverEmail, // Email do driver (chave de busca)
            vehicleType: route.vehicleType,
            startLatitude: parseFloat(route.startLatitude) || 0,
            startLongitude: parseFloat(route.startLongitude) || 0,
            totalDistance: parseFloat(route.totalDistance) || 0,
            totalDeliveries: stops.length,
            totalDuration: parseInt(route.totalDuration) || 0,
            timeWindowStart: route.timeWindowStart || '08:00',
            timeWindowEnd: route.timeWindowEnd || '18:00',
            status: 'rota_enviada', // Enviada automaticamente para o motorista
            sentToDriverAt: nowBrazil()
          };

          // Buscar orderNumber dos billings para cada parada
          const billingIds = stops
            .map((s: any) => s.billingId)
            .filter((id: any) => id);
          
          const billingInfoMap: Record<string, { orderNumber: string; omieOrderId: string }> = {};
          if (billingIds.length > 0) {
            const billingsData = await db.select({
              id: billingsTable.id,
              orderNumber: billingsTable.orderNumber,
              omieOrderId: billingsTable.omieOrderId,
            }).from(billingsTable).where(inArray(billingsTable.id, billingIds));
            
            for (const b of billingsData) {
              billingInfoMap[b.id] = {
                orderNumber: b.orderNumber || '',
                omieOrderId: b.omieOrderId || '',
              };
            }
          }

          const stopsData = stops.map((stop: any, index: number) => ({
            salesCardId: stop.salesCardId,
            billingId: stop.billingId || null,
            orderNumber: (stop.billingId && billingInfoMap[stop.billingId]?.orderNumber) || stop.orderNumber || null,
            omieOrderId: (stop.billingId && billingInfoMap[stop.billingId]?.omieOrderId) || null,
            customerId: stop.customerId,
            customerName: stop.customerName,
            customerAddress: stop.customerAddress,
            customerLatitude: parseFloat(stop.latitude) || 0,
            customerLongitude: parseFloat(stop.longitude) || 0,
            stopOrder: index + 1,
            estimatedArrival: stop.estimatedArrival || null,
            estimatedDeparture: stop.estimatedDeparture || null,
            estimatedServiceTime: parseInt(stop.estimatedServiceTime) || 30,
            distanceFromPrevious: parseFloat(stop.distanceFromPrevious) || 0,
            isPriority: stop.isUrgent || false,
            status: 'pendente'
          }));

          const result = await storage.saveRouteWithStops(routeData, stopsData);
          savedRoute = result.route;
          savedStops = result.stops;
          console.log(`✅ [SAVE-ROUTES] Rota ${routeName} criada com ${savedStops.length} paradas`);
        }
        
        savedRoutes.push({
          ...savedRoute,
          stops: savedStops
        });

        // Coletar billingIds para atualizar status
        const billingIds = stops
          .map((stop: any) => stop.billingId)
          .filter((id: any) => id);
        
        allBillingIds.push(...billingIds);
      }

      // Atualizar status dos billings para "Em Rota"
      if (allBillingIds.length > 0) {
        await storage.updateBillingsStatus(allBillingIds, 'Em Rota');
        console.log(`📦 [SAVE-ROUTES] ${allBillingIds.length} billings atualizados para "Em Rota"`);
        
        // ✅ SINCRONIZAÇÃO OMIE: Alterar etapa das NFs para "Em Rota" (código 20)
        try {
          console.log(`🔄 [OMIE-SYNC] Iniciando sincronização de etapas para ${allBillingIds.length} billings...`);
          
          const billingsData = await db.select({
            id: billings.id,
            omieOrderId: billings.omieOrderId,
            orderNumber: billings.orderNumber,
            invoiceNumber: billings.invoiceNumber,
            customerFantasyName: billings.customerFantasyName,
          }).from(billingsTable).where(inArray(billingsTable.id, allBillingIds));
          
          console.log(`📋 [OMIE-SYNC] Billings encontrados: ${billingsData.length}, com omieOrderId: ${billingsData.filter(b => b.omieOrderId).length}`);
          billingsData.forEach(b => {
            console.log(`  - billing ${b.id}: omieOrderId=${b.omieOrderId || 'NENHUM'}, invoice=${b.invoiceNumber || 'NENHUM'}, customer=${b.customerFantasyName || 'NENHUM'}`);
          });
          
          const ordersToUpdate = billingsData
            .filter(b => b.omieOrderId && !isNaN(parseInt(b.omieOrderId)))
            .map(b => ({
              codigoPedido: parseInt(b.omieOrderId!),
              novaEtapa: OmieService.STAGE_EM_ROTA,
              billingId: b.id,
              invoiceNumber: b.invoiceNumber || '',
              customerName: b.customerFantasyName || '',
            }));
          
          if (ordersToUpdate.length > 0) {
            console.log(`📤 [OMIE-SYNC] Atualizando ${ordersToUpdate.length} pedidos para etapa "Em Rota" (20)...`);
            console.log(`📤 [OMIE-SYNC] Pedidos: ${JSON.stringify(ordersToUpdate.map(o => o.codigoPedido))}`);
            
            const instanceGroups = await getOmieServicesGroupedByInstance(storage, allBillingIds);
            const triggeredBy = (req as any).currentUser?.email || 'system';
            
            for (const [instanceKey, group] of instanceGroups) {
              const instanceOrders = ordersToUpdate.filter(o => group.billingIds.includes(o.billingId));
              if (instanceOrders.length === 0) continue;
              
              console.log(`📤 [OMIE-SYNC] Instance ${instanceKey}: ${instanceOrders.length} pedidos`);
              const resultado = await group.service.trocarEtapasPedidosEmLote(
                instanceOrders.map(o => ({ codigoPedido: o.codigoPedido, novaEtapa: o.novaEtapa }))
              );
              console.log(`✅ [OMIE-SYNC] Instance ${instanceKey}: ${resultado.successCount} sucesso, ${resultado.errorCount} erros`);
              
              for (const orderInfo of instanceOrders) {
                const resultItem = resultado.results.find(r => r.codigoPedido === orderInfo.codigoPedido);
                await logOmieStageChange({
                  omieOrderId: orderInfo.codigoPedido,
                  orderNumber: orderInfo.invoiceNumber,
                  customerName: orderInfo.customerName,
                  newStage: OmieService.STAGE_EM_ROTA,
                  trigger: 'send_to_driver',
                  triggerDetail: `Rota salva e enviada automaticamente`,
                  billingId: orderInfo.billingId,
                  triggeredBy,
                  success: resultItem?.success ?? false,
                  errorMessage: resultItem?.success === false ? resultItem.message : undefined,
                  omieResponse: resultItem || null,
                });
              }
            }
          } else {
            console.log(`⚠️ [OMIE-SYNC] Nenhum billing com omieOrderId válido encontrado`);
          }
        } catch (omieError: any) {
          console.error(`⚠️ [OMIE-SYNC] Erro ao sincronizar com Omie:`, omieError?.message || omieError);
        }
      }

      console.log(`✅ [SAVE-ROUTES] ${savedRoutes.length} rotas salvas com sucesso`);
      console.log(`✅ [SAVE-ROUTES] Rotas salvas:`, savedRoutes.map(r => ({ id: r.id, nome: r.routeName, data: r.routeDate, status: r.status })));

      res.json({
        success: true,
        message: `${savedRoutes.length} rotas salvas com sucesso`,
        routes: savedRoutes
      });
    } catch (error: any) {
      console.error(`❌ [SAVE-ROUTES] ========== ERRO NO SALVAMENTO ==========`);
      console.error(`❌ [SAVE-ROUTES] Timestamp: ${new Date().toISOString()}`);
      console.error(`❌ [SAVE-ROUTES] Mensagem: ${error.message}`);
      console.error(`❌ [SAVE-ROUTES] Stack: ${error.stack}`);
      console.error(`❌ [SAVE-ROUTES] Erro completo:`, error);
      res.status(500).json({ message: "Failed to save delivery routes", error: error.message, stack: error.stack });
    }
  });

  // Buscar rotas de entrega com motorista e paradas
  // Todos os usuários podem visualizar as rotas de entrega
  app.get("/api/delivery-routes", authenticateUser, requireRole(['admin', 'coordinator', 'administrative', 'vendedor', 'telemarketing', 'motorista']), async (req: any, res) => {
    try {
      const { status, routeDate, driverId, savedOnly } = req.query;
      
      const filters: any = {};
      if (status) filters.status = status;
      if (routeDate) filters.routeDate = routeDate; // Manter como string YYYY-MM-DD
      if (driverId) filters.driverId = driverId;
      if (savedOnly === 'true') filters.savedOnly = true;
      
      // storage.getDeliveryRoutes já retorna as paradas, não precisa buscar novamente
      const routes = await storage.getDeliveryRoutes(filters);
      
      res.json(routes);
    } catch (error: any) {
      console.error("Error fetching delivery routes:", error);
      res.status(500).json({ message: "Failed to fetch delivery routes", error: error.message });
    }
  });

