  // ========== ENDPOINTS PARA MOTORISTAS ENTREGADORES ==========
  
  // Buscar rotas do motorista autenticado por EMAIL + DATA
  app.get("/api/delivery-routes/driver/my-routes", authenticateUser, async (req: any, res) => {
    try {
      console.log(`🚀🚀🚀 [DRIVER-ROUTES] ENDPOINT CHAMADO! 🚀🚀🚀`);
      const { date } = req.query;
      const currentUser = (req as any).currentUser;
      const userEmail = currentUser?.email || req.user?.email;
      
      console.log(`[DEBUG] currentUser:`, currentUser);
      console.log(`[DEBUG] req.user:`, req.user);
      console.log(`[DEBUG] userEmail:`, userEmail);
      console.log(`[DEBUG] date param:`, date);
      
      if (!userEmail) {
        console.log(`❌ [DRIVER-ROUTES] Email não encontrado - currentUser:`, currentUser, "req.user:", req.user);
        return res.status(401).json({ message: "Usuário não autenticado com email" });
      }
      
      console.log(`📦 [DRIVER-ROUTES] Buscando rotas do motorista: "${userEmail}" para ${date || 'hoje'}`);
      
      // Construir data alvo
      let targetDateStr: string;
      if (date) {
        targetDateStr = date;
      } else {
        const today = nowBrazil();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        targetDateStr = `${year}-${month}-${day}`;
      }
      
      console.log(`📅 [DRIVER-ROUTES] Data alvo: "${targetDateStr}", Email normalizado: "${userEmail}"`);
      
      // Log da query SQL que será executada
      console.log(`[DEBUG] Procurando rotas com: status IN ['rota_enviada', 'em_andamento', 'concluida'], email="${userEmail}", date="${targetDateStr}"`);
      
      // Buscar rotas diretamente por EMAIL + DATA (sem intermediários)
      // Ajuste: Usando SQL raw para garantir que a comparação de data funcione independente do tipo (timestamp vs text)
      const routes = await db.select().from(deliveryRoutes)
        .where(
          and(
            sql`LOWER(${deliveryRoutes.driverEmail}) = LOWER(${userEmail})`,
            sql`CAST(${deliveryRoutes.routeDate} AS DATE) = CAST(${targetDateStr} AS DATE)`,
            inArray(deliveryRoutes.status, ['rota_salva', 'rota_enviada', 'em_andamento', 'concluida'])
          )
        )
        .orderBy(asc(deliveryRoutes.createdAt));
      
      console.log(`📦 [DRIVER-ROUTES] Query retornou: ${routes.length} rotas`);
      if (routes.length > 0) {
        console.log(`[DEBUG] Primeira rota:`, routes[0]);
      } else {
        // Se não encontrou rotas, fazer diagnóstico
        console.log(`🔍 [DRIVER-ROUTES] Nenhuma rota encontrada. Iniciando diagnóstico...`);
        
        // 1. Verificar se existem rotas para esta data (qualquer motorista)
        const routesForDate = await db.select({
          id: deliveryRoutes.id,
          driverEmail: deliveryRoutes.driverEmail,
          status: deliveryRoutes.status,
          routeDate: deliveryRoutes.routeDate
        }).from(deliveryRoutes)
          .where(sql`CAST(${deliveryRoutes.routeDate} AS DATE) = CAST(${targetDateStr} AS DATE)`);
        
        console.log(`🔍 [DRIVER-ROUTES] Total de rotas para ${targetDateStr}: ${routesForDate.length}`);
        if (routesForDate.length > 0) {
          routesForDate.forEach((r, i) => {
            console.log(`   [${i}] email="${r.driverEmail}", status="${r.status}"`);
          });
        }
        
        // 2. Verificar se existem rotas para este email (qualquer data)
        const routesForEmail = await db.select({
          id: deliveryRoutes.id,
          routeDate: deliveryRoutes.routeDate,
          status: deliveryRoutes.status,
          driverEmail: deliveryRoutes.driverEmail
        }).from(deliveryRoutes)
          .where(sql`LOWER(${deliveryRoutes.driverEmail}) = LOWER(${userEmail})`)
          .orderBy(desc(deliveryRoutes.routeDate))
          .limit(5);
        
        console.log(`🔍 [DRIVER-ROUTES] Rotas recentes do email ${userEmail}: ${routesForEmail.length}`);
        if (routesForEmail.length > 0) {
          routesForEmail.forEach((r, i) => {
            console.log(`   [${i}] date="${r.routeDate}", status="${r.status}"`);
          });
        }
      }
      
      // Buscar paradas para cada rota
      const routesWithStops = await Promise.all(
        routes.map(async (route) => {
          const stops = await db.select().from(deliveryRouteStops)
            .where(eq(deliveryRouteStops.routeId, route.id))
            .orderBy(asc(deliveryRouteStops.stopOrder));
          
          return {
            ...route,
            stops
          };
        })
      );
      
      console.log(`✅ [DRIVER-ROUTES] Encontradas ${routesWithStops.length} rotas para ${userEmail}`);
      res.json(routesWithStops);
    } catch (error: any) {
      console.error("Error fetching driver routes:", error);
      res.status(500).json({ message: "Failed to fetch driver routes", error: error.message });
    }
  });

