  // FIX: Endpoint para corrigir rotas sem email do motorista
  app.post("/api/delivery-routes/fix-missing-emails", async (req: any, res) => {
    try {
      console.log(`🔧 [FIX-EMAILS] Corrigindo rotas sem email de motorista...`);
      
      // Buscar rotas sem email
      const routesWithoutEmail = await db.select().from(deliveryRoutes)
        .where(sql`${deliveryRoutes.driverEmail} IS NULL OR ${deliveryRoutes.driverEmail} = ''`);
      
      console.log(`🔍 [FIX-EMAILS] Encontradas ${routesWithoutEmail.length} rotas sem email`);
      
      const fixed: any[] = [];
      const notFixed: any[] = [];
      
      for (const route of routesWithoutEmail) {
        // Tentar buscar email do driver na tabela deliveryDrivers
        let driverEmail: string | null = null;
        
        if (route.driverId) {
          const driver = await db.select().from(deliveryDrivers)
            .where(eq(deliveryDrivers.id, route.driverId))
            .limit(1);
          
          if (driver.length > 0 && driver[0].email) {
            driverEmail = driver[0].email;
          }
        }
        
        // Se não encontrou, tentar buscar pelo nome do motorista na tabela users
        if (!driverEmail && route.driverName) {
          const allDrivers = await db.select().from(users)
            .where(eq(users.role, 'motorista'));
          
          // Buscar por correspondência de nome (case insensitive) usando firstName
          const matchingDriver = allDrivers.find(u => {
            const fullName = `${u.firstName || ''} ${u.lastName || ''}`.trim();
            return fullName.toLowerCase().includes(route.driverName!.toLowerCase()) ||
                   (u.firstName && u.firstName.toLowerCase().includes(route.driverName!.toLowerCase()));
          });
          
          if (matchingDriver?.email) {
            driverEmail = matchingDriver.email;
          }
        }
        
        if (driverEmail) {
          // Atualizar a rota com o email encontrado
          await db.update(deliveryRoutes)
            .set({ driverEmail, updatedAt: nowBrazil() })
            .where(eq(deliveryRoutes.id, route.id));
          
          fixed.push({
            id: route.id,
            routeName: route.routeName,
            driverName: route.driverName,
            fixedEmail: driverEmail
          });
          console.log(`✅ [FIX-EMAILS] Rota ${route.routeName} corrigida com email ${driverEmail}`);
        } else {
          notFixed.push({
            id: route.id,
            routeName: route.routeName,
            driverName: route.driverName,
            driverId: route.driverId
          });
          console.log(`❌ [FIX-EMAILS] Não foi possível encontrar email para rota ${route.routeName}`);
        }
      }
      
      res.json({
        message: `Correção concluída: ${fixed.length} rotas corrigidas, ${notFixed.length} não corrigidas`,
        fixed,
        notFixed
      });
    } catch (error: any) {
      console.error("Error fixing missing emails:", error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // DEBUG: Diagnóstico e sincronização forçada de etapas Omie para uma rota
  app.post("/api/delivery-routes/:routeId/force-omie-sync", async (req: any, res) => {
    try {
      const { routeId } = req.params;
      console.log(`🔍 [FORCE-OMIE-SYNC] Verificando rota ${routeId}`);
      
      // Buscar a rota
      const route = await db.select().from(deliveryRoutes)
        .where(eq(deliveryRoutes.id, routeId))
        .limit(1);
      
      if (route.length === 0) {
        return res.status(404).json({ message: "Rota não encontrada" });
      }
      
      const routeData = route[0];
      
      // Buscar paradas da rota
      const stops = await db.select().from(deliveryRouteStops)
        .where(eq(deliveryRouteStops.routeId, routeId));
      
      console.log(`📋 [FORCE-OMIE-SYNC] Rota ${routeData.routeName} tem ${stops.length} paradas`);
      
      // Diagnóstico das paradas
      const stopsWithBilling: any[] = [];
      const stopsWithoutBilling: any[] = [];
      const billingsWithOmieId: any[] = [];
      const billingsWithoutOmieId: any[] = [];
      
      for (const stop of stops) {
        const stopInfo = {
          stopId: stop.id,
          customerName: stop.customerName,
          billingId: stop.billingId
        };
        
        if (stop.billingId) {
          stopsWithBilling.push(stopInfo);
          
          // Verificar billing
          const billing = await db.select().from(billingsTable)
            .where(eq(billingsTable.id, stop.billingId))
            .limit(1);
          
          if (billing.length > 0) {
            const billingInfo = {
              billingId: billing[0].id,
              omieOrderId: billing[0].omieOrderId,
              orderNumber: billing[0].orderNumber,
              customerName: stop.customerName
            };
            
            if (billing[0].omieOrderId && !isNaN(parseInt(billing[0].omieOrderId))) {
              billingsWithOmieId.push(billingInfo);
            } else {
              billingsWithoutOmieId.push(billingInfo);
            }
          }
        } else {
          stopsWithoutBilling.push(stopInfo);
        }
      }
      
      console.log(`📊 [FORCE-OMIE-SYNC] Diagnóstico:`);
      console.log(`   - Paradas com billingId: ${stopsWithBilling.length}`);
      console.log(`   - Paradas SEM billingId: ${stopsWithoutBilling.length}`);
      console.log(`   - Billings com omieOrderId: ${billingsWithOmieId.length}`);
      console.log(`   - Billings SEM omieOrderId: ${billingsWithoutOmieId.length}`);
      
      // Forçar sincronização com Omie se houver billings válidos
      let omieResult = null;
      if (billingsWithOmieId.length > 0) {
        console.log(`🔄 [FORCE-OMIE-SYNC] Forçando sincronização de ${billingsWithOmieId.length} pedidos...`);
        
        const pedidosParaAlterar = billingsWithOmieId.map((b: any) => ({
          codigoPedido: parseInt(b.omieOrderId),
          novaEtapa: OmieService.STAGE_EM_ROTA
        }));
        
        try {
          const billingIdsForSync = billingsWithOmieId.map((b: any) => b.billingId);
          const instanceGroups = await getOmieServicesGroupedByInstance(storage, billingIdsForSync);
          let totalSuccess = 0, totalErrors = 0;
          const allResults: any[] = [];
          
          for (const [instanceKey, group] of instanceGroups) {
            const instancePedidos = pedidosParaAlterar.filter((_: any, i: number) => 
              group.billingIds.includes(billingsWithOmieId[i]?.billingId)
            );
            if (instancePedidos.length === 0) continue;
            
            const resultado = await group.service.trocarEtapasPedidosEmLote(instancePedidos);
            totalSuccess += resultado.successCount;
            totalErrors += resultado.errorCount;
            allResults.push(...(resultado.results || []));
          }
          omieResult = { successCount: totalSuccess, errorCount: totalErrors, results: allResults };
          console.log(`✅ [FORCE-OMIE-SYNC] Resultado: ${totalSuccess} sucesso, ${totalErrors} erros`);
        } catch (omieError: any) {
          omieResult = { error: omieError.message };
          console.error(`❌ [FORCE-OMIE-SYNC] Erro:`, omieError);
        }
      }
      
      res.json({
        route: {
          id: routeData.id,
          routeName: routeData.routeName,
          routeDate: routeData.routeDate,
          status: routeData.status,
          driverEmail: routeData.driverEmail,
          totalDeliveries: routeData.totalDeliveries
        },
        diagnostic: {
          totalStops: stops.length,
          stopsWithBilling: stopsWithBilling.length,
          stopsWithoutBilling: stopsWithoutBilling.length,
          billingsWithOmieId: billingsWithOmieId.length,
          billingsWithoutOmieId: billingsWithoutOmieId.length
        },
        details: {
          stopsWithoutBilling,
          billingsWithoutOmieId
        },
        omieSync: billingsWithOmieId.length > 0 ? {
          attempted: true,
          ordersToSync: billingsWithOmieId.map((b: any) => b.omieOrderId),
          result: omieResult
        } : {
          attempted: false,
          reason: "Nenhum billing com omieOrderId válido encontrado",
          suggestion: "Use o endpoint /api/billings/fix-missing-omie-ids para tentar preencher os omieOrderIds faltantes"
        }
      });
    } catch (error: any) {
      console.error("Error in force-omie-sync:", error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Endpoint para tentar preencher omieOrderId faltantes nos billings
  app.post("/api/billings/fix-missing-omie-ids", async (req: any, res) => {
    try {
      console.log(`🔧 [FIX-OMIE-IDS] Buscando billings sem omieOrderId...`);
      
      // Buscar billings sem omieOrderId
      const billingsWithoutOmieId = await db.select().from(billingsTable)
        .where(
          and(
            or(
              isNull(billingsTable.omieOrderId),
              eq(billingsTable.omieOrderId, '')
            ),
            // Apenas billings não cancelados e com número de pedido
            eq(billingsTable.isCancelled, false),
            isNotNull(billingsTable.orderNumber)
          )
        )
        .limit(50); // Limitar para evitar timeout
      
      console.log(`🔍 [FIX-OMIE-IDS] Encontrados ${billingsWithoutOmieId.length} billings sem omieOrderId`);
      
      const fixed: any[] = [];
      const notFixed: any[] = [];
      
      const omie = getOmieService(storage);
      if (!omie) {
        return res.status(400).json({ error: "Omie não configurado" });
      }
      
      for (const billing of billingsWithoutOmieId) {
        try {
          // Tentar buscar o pedido no Omie pelo número
          console.log(`🔍 [FIX-OMIE-IDS] Buscando pedido ${billing.orderNumber}...`);
          
          // Usar o número do pedido para buscar no Omie
          const searchResult = await omie.buscarPedidoPorNumero(billing.orderNumber);
          
          if (searchResult && searchResult.nCodPed) {
            const omieOrderId = String(searchResult.nCodPed);
            
            // Atualizar o billing com o omieOrderId
            await db.update(billingsTable)
              .set({ omieOrderId })
              .where(eq(billingsTable.id, billing.id));
            
            fixed.push({
              billingId: billing.id,
              orderNumber: billing.orderNumber,
              omieOrderId: omieOrderId
            });
            
            console.log(`✅ [FIX-OMIE-IDS] Billing ${billing.id} atualizado com omieOrderId ${omieOrderId}`);
          } else {
            notFixed.push({
              billingId: billing.id,
              orderNumber: billing.orderNumber,
              reason: "Pedido não encontrado no Omie"
            });
            console.log(`⚠️ [FIX-OMIE-IDS] Pedido ${billing.orderNumber} não encontrado no Omie`);
          }
        } catch (error: any) {
          notFixed.push({
            billingId: billing.id,
            orderNumber: billing.orderNumber,
            reason: error.message
          });
          console.error(`❌ [FIX-OMIE-IDS] Erro ao buscar pedido ${billing.orderNumber}:`, error.message);
        }
        
        // Delay para não sobrecarregar a API Omie
        await new Promise(resolve => setTimeout(resolve, 200));
      }
      
      res.json({
        message: `Processados ${billingsWithoutOmieId.length} billings: ${fixed.length} corrigidos, ${notFixed.length} não corrigidos`,
        fixed,
        notFixed
      });
    } catch (error: any) {
      console.error("Error fixing missing omie ids:", error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Endpoint para atualizar um billing específico com orderNumber e buscar omieOrderId
  app.post("/api/billings/:billingId/set-order-number", async (req: any, res) => {
    try {
      const { billingId } = req.params;
      const { orderNumber } = req.body;
      
      if (!orderNumber) {
        return res.status(400).json({ error: "orderNumber é obrigatório" });
      }
      
      console.log(`🔧 [SET-ORDER] Atualizando billing ${billingId} com orderNumber ${orderNumber}`);
      
      // Verificar se o billing existe
      const existingBilling = await db.select().from(billingsTable)
        .where(eq(billingsTable.id, billingId))
        .limit(1);
      
      if (existingBilling.length === 0) {
        return res.status(404).json({ error: "Billing não encontrado" });
      }
      
      // Buscar o omieOrderId no Omie
      const omie = getOmieService(storage);
      let omieOrderId: string | null = null;
      
      if (omie) {
        const searchResult = await omie.buscarPedidoPorNumero(orderNumber);
        if (searchResult && searchResult.nCodPed) {
          omieOrderId = String(searchResult.nCodPed);
          console.log(`✅ [SET-ORDER] Encontrado omieOrderId ${omieOrderId} para pedido ${orderNumber}`);
        }
      }
      
      // Atualizar o billing
      await db.update(billingsTable)
        .set({ 
          orderNumber,
          ...(omieOrderId ? { omieOrderId } : {})
        })
        .where(eq(billingsTable.id, billingId));
      
      res.json({
        success: true,
        billingId,
        orderNumber,
        omieOrderId,
        message: omieOrderId 
          ? `Billing atualizado com orderNumber ${orderNumber} e omieOrderId ${omieOrderId}`
          : `Billing atualizado com orderNumber ${orderNumber}, mas omieOrderId não encontrado no Omie`
      });
    } catch (error: any) {
      console.error("Error setting order number:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Enviar rota para o motorista (muda status de 'rota salva' para 'rota_enviada')
  // Também altera etapas das NFs no Omie para "Em Rota" (20)
  app.post("/api/delivery-routes/:routeId/send-to-driver", authenticateUser, requireRole(['admin', 'coordinator', 'administrative']), async (req: any, res) => {
    try {
      const { routeId } = req.params;
      
      console.log(`📤 [SEND-ROUTE] Enviando rota ${routeId} para o motorista`);
      
      // Buscar a rota
      const route = await db.select().from(deliveryRoutes)
        .where(eq(deliveryRoutes.id, routeId))
        .limit(1);
      
      if (route.length === 0) {
        return res.status(404).json({ message: "Rota não encontrada" });
      }
      
      // Buscar todas as paradas da rota para obter os omieOrderIds
      const stops = await db.select().from(deliveryRouteStops)
        .where(eq(deliveryRouteStops.routeId, routeId));
      
      // Coletar omieOrderIds dos billings relacionados às paradas
      const orderInfos: Array<{ orderId: number; billingId: string; customerName: string; orderNumber: string; stopId: string }> = [];
      for (const stop of stops) {
        if (stop.billingId) {
          const billing = await db.select().from(billingsTable)
            .where(eq(billingsTable.id, stop.billingId))
            .limit(1);
          if (billing.length > 0 && billing[0].omieOrderId) {
            const orderId = parseInt(billing[0].omieOrderId);
            if (!isNaN(orderId)) {
              orderInfos.push({
                orderId,
                billingId: stop.billingId,
                customerName: billing[0].customerFantasyName || stop.customerName || '',
                orderNumber: billing[0].invoiceNumber || '',
                stopId: stop.id,
              });
            }
          }
        }
      }
      
      const triggeredBy = (req as any).currentUser?.email || 'system';
      
      // Alterar etapas no Omie para "Em Rota" - SÍNCRONO para garantir execução
      if (orderInfos.length > 0) {
        console.log(`🔄 [SEND-ROUTE] Alterando ${orderInfos.length} pedidos para etapa "Em Rota" no Omie...`);
        
        try {
          console.log(`🔍 [SEND-ROUTE] Inicializando OmieService por instância...`);
          const billingIdsForSync = orderInfos.map(info => info.billingId);
          const instanceGroups = await getOmieServicesGroupedByInstance(storage, billingIdsForSync);
          
          for (const [instanceKey, group] of instanceGroups) {
            const instanceInfos = orderInfos.filter(info => group.billingIds.includes(info.billingId));
            if (instanceInfos.length === 0) continue;
            
            const pedidosParaAlterar = instanceInfos.map(info => ({
              codigoPedido: info.orderId,
              novaEtapa: OmieService.STAGE_EM_ROTA
            }));
            
            console.log(`📋 [SEND-ROUTE] Instance ${instanceKey}: ${pedidosParaAlterar.length} pedidos`);
            const resultado = await group.service.trocarEtapasPedidosEmLote(pedidosParaAlterar);
            console.log(`✅ [SEND-ROUTE] Instance ${instanceKey}: ${resultado.successCount} sucesso, ${resultado.errorCount} erros`);
            
            for (const info of instanceInfos) {
              const resultItem = resultado.results.find(r => r.codigoPedido === info.orderId);
              await logOmieStageChange({
                omieOrderId: info.orderId,
                orderNumber: info.orderNumber,
                customerName: info.customerName,
                newStage: OmieService.STAGE_EM_ROTA,
                trigger: 'send_to_driver',
                triggerDetail: `Rota enviada para motorista`,
                routeId,
                stopId: info.stopId,
                billingId: info.billingId,
                driverEmail: route[0].driverEmail || undefined,
                triggeredBy,
                success: resultItem?.success ?? true,
                errorMessage: resultItem?.success === false ? resultItem.message : undefined,
                omieResponse: resultItem || null,
              });
            }
          }
        } catch (error: any) {
          console.error(`❌ [SEND-ROUTE] Erro ao alterar etapas no Omie:`, error?.message || error);
          for (const info of orderInfos) {
            await logOmieStageChange({
              omieOrderId: info.orderId,
              orderNumber: info.orderNumber,
              customerName: info.customerName,
              newStage: OmieService.STAGE_EM_ROTA,
              trigger: 'send_to_driver',
              triggerDetail: `Rota enviada para motorista`,
              routeId,
              billingId: info.billingId,
              triggeredBy,
              success: false,
              errorMessage: error?.message || 'Erro desconhecido',
            });
          }
        }
      }
      
      // Atualizar status da rota para 'rota_enviada'
      const updatedRoute = await db.update(deliveryRoutes)
        .set({ 
          status: 'rota_enviada', 
          sentToDriverAt: nowBrazil(),
          updatedAt: nowBrazil() 
        })
        .where(eq(deliveryRoutes.id, routeId))
        .returning();
      
      console.log(`✅ [SEND-ROUTE] Rota ${routeId} enviada para o motorista`);
      res.json({ 
        message: "Rota enviada para o motorista com sucesso", 
        route: updatedRoute[0],
        omieUpdates: orderInfos.length > 0 ? `${orderInfos.length} pedidos sendo atualizados para "Em Rota"` : null
      });
    } catch (error: any) {
      console.error("Error sending route to driver:", error);
      res.status(500).json({ message: "Failed to send route to driver", error: error.message });
    }
  });

  // Sincronizar etapas Omie para TODAS as rotas de um dia - muda todos os pedidos para "Em Rota" (20)
  app.post("/api/delivery-routes/sync-omie-stages-day", authenticateUser, requireRole(['admin', 'coordinator', 'administrative']), async (req: any, res) => {
    try {
      const { date } = req.body;
      const triggeredBy = (req as any).currentUser?.email || 'system';
      
      if (!date) {
        return res.status(400).json({ message: "Data é obrigatória" });
      }
      
      console.log(`🔄 [SYNC-OMIE-DAY] Sincronizando etapas de TODAS as rotas do dia ${date} para "Em Rota" (20)`);
      
      const routes = await db.select().from(deliveryRoutes)
        .where(and(
          sql`${deliveryRoutes.routeDate}::text = ${date}`,
          inArray(deliveryRoutes.status, ['rota_salva', 'rota_enviada', 'em_andamento'])
        ));
      
      if (routes.length === 0) {
        return res.json({ message: "Nenhuma rota encontrada para esta data", successCount: 0, errorCount: 0, results: [] });
      }
      
      console.log(`📋 [SYNC-OMIE-DAY] Encontradas ${routes.length} rotas para ${date}`);
      
      const allRouteIds = routes.map(r => r.id);
      const allStops = await db.select().from(deliveryRouteStops)
        .where(inArray(deliveryRouteStops.routeId, allRouteIds));
      
      const orderInfos: Array<{ orderId: number; orderNumber: string; customerName: string; stopId: string; routeId: string; billingId: string; driverEmail: string }> = [];
      
      for (const stop of allStops) {
        let omieId = stop.omieOrderId ? parseInt(stop.omieOrderId) : NaN;
        
        if (isNaN(omieId) && stop.billingId) {
          const billing = await db.select().from(billingsTable)
            .where(eq(billingsTable.id, stop.billingId))
            .limit(1);
          if (billing.length > 0 && billing[0].omieOrderId) {
            omieId = parseInt(billing[0].omieOrderId);
            if (!isNaN(omieId)) {
              await db.update(deliveryRouteStops)
                .set({ 
                  omieOrderId: billing[0].omieOrderId,
                  orderNumber: billing[0].orderNumber || stop.orderNumber,
                })
                .where(eq(deliveryRouteStops.id, stop.id));
            }
          }
        }
        
        if (!isNaN(omieId)) {
          const route = routes.find(r => r.id === stop.routeId);
          orderInfos.push({
            orderId: omieId,
            orderNumber: stop.orderNumber || '',
            customerName: stop.customerName || '',
            stopId: stop.id,
            routeId: stop.routeId,
            billingId: stop.billingId || '',
            driverEmail: route?.driverEmail || '',
          });
        }
      }
      
      if (orderInfos.length === 0) {
        return res.json({ message: "Nenhum pedido Omie encontrado nas rotas", successCount: 0, errorCount: 0, results: [] });
      }
      
      console.log(`📤 [SYNC-OMIE-DAY] Sincronizando ${orderInfos.length} pedidos para "Em Rota" (20)...`);
      
      const billingIdsForSync = orderInfos.filter(i => i.billingId).map(i => i.billingId);
      const instanceGroups = billingIdsForSync.length > 0 
        ? await getOmieServicesGroupedByInstance(storage, billingIdsForSync)
        : new Map();
      
      let totalSuccess = 0, totalErrors = 0;
      const allResults: any[] = [];
      
      for (const [instanceKey, group] of instanceGroups) {
        const instanceInfos = orderInfos.filter(info => group.billingIds.includes(info.billingId));
        if (instanceInfos.length === 0) continue;
        
        const pedidosParaAlterar = instanceInfos.map(info => ({
          codigoPedido: info.orderId,
          novaEtapa: OmieService.STAGE_EM_ROTA
        }));
        
        const resultado = await group.service.trocarEtapasPedidosEmLote(pedidosParaAlterar);
        totalSuccess += resultado.successCount;
        totalErrors += resultado.errorCount;
        allResults.push(...(resultado.results || []));
        
        for (const info of instanceInfos) {
          const resultItem = resultado.results.find(r => r.codigoPedido === info.orderId);
          await logOmieStageChange({
            omieOrderId: info.orderId,
            orderNumber: info.orderNumber,
            customerName: info.customerName,
            newStage: OmieService.STAGE_EM_ROTA,
            trigger: 'send_to_driver',
            triggerDetail: `Sincronização manual - todas as rotas do dia ${date}`,
            routeId: info.routeId,
            stopId: info.stopId,
            billingId: info.billingId,
            driverEmail: info.driverEmail,
            triggeredBy,
            success: resultItem?.success ?? false,
            errorMessage: resultItem?.success === false ? resultItem.message : undefined,
            omieResponse: resultItem || null,
          });
        }
      }
      console.log(`✅ [SYNC-OMIE-DAY] Resultado total: ${totalSuccess} sucesso, ${totalErrors} erros`);
      
      res.json({
        message: `Sincronização concluída: ${totalSuccess} sucesso, ${totalErrors} erros de ${orderInfos.length} pedidos`,
        successCount: totalSuccess,
        errorCount: totalErrors,
        totalOrders: orderInfos.length,
        results: allResults,
      });
    } catch (error: any) {
      console.error("Error syncing Omie stages for day:", error);
      res.status(500).json({ message: "Erro ao sincronizar etapas Omie", error: error.message });
    }
  });

  // Enviar todas as rotas do dia para os motoristas
  // Também altera etapas das NFs no Omie para "Em Rota" (20)
  app.post("/api/delivery-routes/send-all-to-drivers", authenticateUser, requireRole(['admin', 'coordinator', 'administrative']), async (req: any, res) => {
    try {
      const { date } = req.body;
      const targetDate = date || getBrazilDateString();
      
      console.log(`📤 [SEND-ALL-ROUTES] Enviando todas as rotas de ${targetDate} para os motoristas`);
      
      // Buscar todas as rotas com status 'rota salva' ou 'pending' para a data
      const routesToSend = await db.select().from(deliveryRoutes)
        .where(
          and(
            sql`CAST(${deliveryRoutes.routeDate} AS DATE) = CAST(${targetDate} AS DATE)`,
            sql`${deliveryRoutes.status} IN ('rota salva', 'pending')`
          )
        );
      
      if (routesToSend.length === 0) {
        return res.json({ message: "Nenhuma rota para enviar", sent: 0 });
      }
      
      // Coletar todos os orderInfos de todas as rotas
      const allOrderInfos: Array<{ orderId: number; billingId: string; customerName: string; orderNumber: string; routeId: string; driverEmail: string }> = [];
      for (const route of routesToSend) {
        const stops = await db.select().from(deliveryRouteStops)
          .where(eq(deliveryRouteStops.routeId, route.id));
        
        for (const stop of stops) {
          if (stop.billingId) {
            const billing = await db.select().from(billingsTable)
              .where(eq(billingsTable.id, stop.billingId))
              .limit(1);
            if (billing.length > 0 && billing[0].omieOrderId) {
              const orderId = parseInt(billing[0].omieOrderId);
              if (!isNaN(orderId) && !allOrderInfos.some(o => o.orderId === orderId)) {
                allOrderInfos.push({
                  orderId,
                  billingId: stop.billingId,
                  customerName: billing[0].customerFantasyName || stop.customerName || '',
                  orderNumber: billing[0].invoiceNumber || '',
                  routeId: route.id,
                  driverEmail: route.driverEmail || '',
                });
              }
            }
          }
        }
      }
      
      const triggeredBy = (req as any).currentUser?.email || 'system';
      
      // Atualizar todas para 'rota_enviada'
      const routeIds = routesToSend.map(r => r.id);
      await db.update(deliveryRoutes)
        .set({ 
          status: 'rota_enviada', 
          sentToDriverAt: nowBrazil(),
          updatedAt: nowBrazil() 
        })
        .where(inArray(deliveryRoutes.id, routeIds));
      
      // Alterar etapas no Omie para "Em Rota" - SÍNCRONO para garantir execução
      if (allOrderInfos.length > 0) {
        console.log(`🔄 [SEND-ALL-ROUTES] Alterando ${allOrderInfos.length} pedidos para etapa "Em Rota" no Omie...`);
        
        try {
          const billingIdsForSync = allOrderInfos.filter(i => i.billingId).map(i => i.billingId);
          const instanceGroups = billingIdsForSync.length > 0
            ? await getOmieServicesGroupedByInstance(storage, billingIdsForSync)
            : new Map();
          
          for (const [instanceKey, group] of instanceGroups) {
            const instanceInfos = allOrderInfos.filter(info => group.billingIds.includes(info.billingId));
            if (instanceInfos.length === 0) continue;
            
            const pedidosParaAlterar = instanceInfos.map(info => ({
              codigoPedido: info.orderId,
              novaEtapa: OmieService.STAGE_EM_ROTA
            }));
            
            console.log(`📋 [SEND-ALL-ROUTES] Instance ${instanceKey}: ${pedidosParaAlterar.length} pedidos`);
            const resultado = await group.service.trocarEtapasPedidosEmLote(pedidosParaAlterar);
            console.log(`✅ [SEND-ALL-ROUTES] Instance ${instanceKey}: ${resultado.successCount} sucesso, ${resultado.errorCount} erros`);
            
            for (const info of instanceInfos) {
              const resultItem = resultado.results.find(r => r.codigoPedido === info.orderId);
              await logOmieStageChange({
                omieOrderId: info.orderId,
                orderNumber: info.orderNumber,
                customerName: info.customerName,
                newStage: OmieService.STAGE_EM_ROTA,
                trigger: 'send_all_to_drivers',
                triggerDetail: `Envio em lote de rotas do dia ${targetDate}`,
                routeId: info.routeId,
                billingId: info.billingId,
                driverEmail: info.driverEmail,
                triggeredBy,
                success: resultItem?.success ?? true,
                errorMessage: resultItem?.success === false ? resultItem.message : undefined,
                omieResponse: resultItem || null,
              });
            }
          }
        } catch (error: any) {
          console.error(`❌ [SEND-ALL-ROUTES] Erro ao alterar etapas no Omie:`, error?.message || error);
          for (const info of allOrderInfos) {
            await logOmieStageChange({
              omieOrderId: info.orderId,
              orderNumber: info.orderNumber,
              customerName: info.customerName,
              newStage: OmieService.STAGE_EM_ROTA,
              trigger: 'send_all_to_drivers',
              triggerDetail: `Envio em lote de rotas do dia ${targetDate}`,
              routeId: info.routeId,
              billingId: info.billingId,
              triggeredBy,
              success: false,
              errorMessage: error?.message || 'Erro desconhecido',
            });
          }
        }
      }
      
      console.log(`✅ [SEND-ALL-ROUTES] ${routesToSend.length} rotas enviadas`);
      res.json({ 
        message: `${routesToSend.length} rotas enviadas para os motoristas`,
        sent: routesToSend.length,
        omieUpdates: allOrderInfos.length > 0 ? `${allOrderInfos.length} pedidos sendo atualizados para "Em Rota"` : null
      });
    } catch (error: any) {
      console.error("Error sending all routes:", error);
      res.status(500).json({ message: "Failed to send routes", error: error.message });
    }
  });

  // Iniciar rota de entrega
