  // Estado global de sincronização para SSE

  // Endpoint SSE para progresso de sincronização
  // Endpoint REST para estado atual do sync (fallback para SSE em produção)
  app.get('/api/omie/sync-billings/state', (req: any, res) => {
    try {
      const stateToSend = {
        ...billingSyncState,
        startedAt: billingSyncState.startedAt?.toISOString() || null,
        completedAt: billingSyncState.completedAt?.toISOString() || null
      };
      res.json(stateToSend);
    } catch (error) {
      res.status(500).json({ message: 'Erro ao obter estado do sync' });
    }
  });

  app.get('/api/omie/sync-billings/progress', (req, res) => {
    try {
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache, no-transform');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('X-Accel-Buffering', 'no');
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.flushHeaders();

      const sendProgress = () => {
        try {
          const stateToSend = {
            ...billingSyncState,
            startedAt: billingSyncState.startedAt?.toISOString() || null,
            completedAt: billingSyncState.completedAt?.toISOString() || null
          };
          const written = res.write(`data: ${JSON.stringify(stateToSend)}\n\n`);
          if (!written) {
            console.log('SSE: backpressure detected, client may be slow');
          }
        } catch (writeError) {
          clearInterval(interval);
        }
      };

      sendProgress();
      const interval = setInterval(sendProgress, 1000);

      req.on('close', () => {
        clearInterval(interval);
      });

      res.on('error', () => {
        clearInterval(interval);
      });
    } catch (error) {
      console.error('Error in SSE progress endpoint:', error);
      res.status(500).json({ message: 'Erro no endpoint de progresso' });
    }
  });

  // Reset sync state if stuck for more than 10 minutes
  app.post('/api/omie/sync-billings/reset', async (req: any, res) => {
    billingSyncState.status = 'idle';
    billingSyncState.currentPage = 0;
    billingSyncState.totalPages = 0;
    billingSyncState.invoicesFound = 0;
    billingSyncState.invoicesProcessed = 0;
    billingSyncState.inserted = 0;
    billingSyncState.updated = 0;
    billingSyncState.currentInvoice = '';
    billingSyncState.message = '';
    billingSyncState.startedAt = null;
    billingSyncState.completedAt = null;
    res.json({ message: 'Estado de sincronização resetado' });
  });

  // Sincronizar faturamentos do Omie - OTIMIZADO: usa syncAllOrders com caches pré-carregados
  app.post('/api/omie/sync-billings', async (req: any, res) => {
    try {
      if (isBillingSyncRunning()) {
        return res.status(409).json({ message: 'Sincronização já em andamento' });
      }

      const instances = await storage.getOmieInstances();
      const activeInstances = instances.filter((i: any) => i.isActive && i.appKey && i.appSecret);

      if (activeInstances.length === 0) {
        const fallback = getOmieService(storage);
        if (!fallback) {
          return res.status(500).json({ message: 'Nenhuma instância Omie configurada' });
        }
        activeInstances.push({ id: fallback.omieInstanceId, name: 'Default', appKey: fallback['appKey'], appSecret: fallback['appSecret'] });
      }

      billingSyncState.status = 'running';
      billingSyncState.currentPage = 0;
      billingSyncState.totalPages = 0;
      billingSyncState.invoicesFound = 0;
      billingSyncState.invoicesProcessed = 0;
      billingSyncState.inserted = 0;
      billingSyncState.updated = 0;
      billingSyncState.currentInvoice = '';
      billingSyncState.message = `Iniciando sincronização de ${activeInstances.length} instância(s)...`;
      billingSyncState.startedAt = nowBrazil();
      billingSyncState.completedAt = null;

      // Persistir início no banco para que o UI mostre "Última tentativa" mesmo se SSE cair
      await storage.updateSyncStatus('omie_billings', {
        status: 'in_progress',
        message: `Sincronização manual iniciada (${activeInstances.length} instância(s))...`,
        recordsProcessed: 0,
        currentProgress: 0,
        lastSyncAt: new Date()
      });

      res.status(202).json({ message: `Sincronização de ${activeInstances.length} instância(s) iniciada em background.` });

      console.log(`\n💰 [SYNC-PEDIDOS] SINCRONIZANDO PEDIDOS DE ${activeInstances.length} INSTÂNCIA(S) OMIE (paralelo)...\n`);

      const syncStartTime = Date.now();
      const totals = { totalProcessed: 0, imported: 0, updated: 0, skipped: 0 };
      // Contadores por instância para progress reporting paralelo
      const instanceProgress: Record<string, { processed: number; imported: number; updated: number }> = {};

      // Rodar todas as instâncias em paralelo para máxima velocidade
      const instanceResults = await Promise.allSettled(
        activeInstances.map(async (inst) => {
          const instanceLabel = inst.name || inst.id;
          instanceProgress[instanceLabel] = { processed: 0, imported: 0, updated: 0 };
          console.log(`\n🏢 [SYNC-PEDIDOS] Iniciando ${instanceLabel}...`);

          const svc = await getOmieServiceForInstance(storage, inst.id);
          if (!svc) {
            console.log(`⚠️ [SYNC-PEDIDOS] ${instanceLabel}: sem credenciais válidas, pulando...`);
            return { instanceLabel, totalProcessed: 0, imported: 0, updated: 0, skipped: 0 };
          }

          const result = await svc.syncAllOrders((progress) => {
            instanceProgress[instanceLabel].processed = progress.invoicesProcessed;
            instanceProgress[instanceLabel].imported = progress.inserted;
            instanceProgress[instanceLabel].updated = progress.updated;
            const totalSoFar = Object.values(instanceProgress).reduce((a, b) => a + b.processed, 0);
            billingSyncState.invoicesProcessed = totalSoFar;
            billingSyncState.invoicesFound = totalSoFar;
            billingSyncState.message = `[${instanceLabel}] ${progress.message || `${progress.invoicesProcessed} pedidos`} | ${Object.keys(instanceProgress).length}/${activeInstances.length} instâncias ativas`;
          });

          console.log(`✅ [SYNC-PEDIDOS] ${instanceLabel}: ${result.totalProcessed} processados, ${result.imported} inseridos, ${result.updated} atualizados`);
          return { instanceLabel, ...result };
        })
      );

      for (const res of instanceResults) {
        if (res.status === 'fulfilled') {
          totals.totalProcessed += res.value.totalProcessed || 0;
          totals.imported += res.value.imported || 0;
          totals.updated += res.value.updated || 0;
          totals.skipped += res.value.skipped || 0;
        } else {
          console.error(`❌ [SYNC-PEDIDOS] Erro em instância:`, res.reason?.message);
        }
      }

      billingSyncState.status = 'completed';
      billingSyncState.invoicesFound = totals.totalProcessed;
      billingSyncState.invoicesProcessed = totals.totalProcessed;
      billingSyncState.inserted = totals.imported;
      billingSyncState.updated = totals.updated;
      const rejectedNote = totals.skipped > 0 ? ` (${totals.skipped} rejeitados)` : '';
      const completionMsg = `Sincronização de ${activeInstances.length} instância(s) concluída! ${totals.imported} inseridos, ${totals.updated} atualizados.${rejectedNote}`;
      billingSyncState.message = completionMsg;
      billingSyncState.completedAt = nowBrazil();

      // Persistir conclusão no banco para atualizar "Última conclusão" no UI
      const syncDurationSeconds = Math.round((Date.now() - syncStartTime) / 1000);
      await storage.updateSyncStatus('omie_billings', {
        status: 'success',
        message: completionMsg,
        lastFinishedAt: new Date(),
        currentProgress: 100,
        recordsProcessed: totals.totalProcessed,
        syncDurationSeconds
      });

      console.log(`\n✅ [SYNC-PEDIDOS] Sincronização multi-instância concluída!`);
      console.log(`📥 Total inseridos: ${totals.imported}`);
      console.log(`🔄 Total atualizados: ${totals.updated}`);
      console.log(`⏭️ Total rejeitados: ${totals.skipped}\n`);

      // Enriquecimento automático de NFs + correção retroativa de vendedores em background
      setImmediate(async () => {
        // 1. Correção retroativa de seller_id/seller_name via JOIN com customers
        try {
          console.log(`\n👤 [SELLER-FIX] Corrigindo seller_id/seller_name retroativamente...`);
          const sellerFixResult = await db.execute(sql`
            UPDATE billings b
            SET 
              seller_id = c.seller_id,
              seller_name = TRIM(CONCAT(COALESCE(u.first_name, ''), ' ', COALESCE(u.last_name, '')))
            FROM customers c
            JOIN users u ON u.id = c.seller_id
            WHERE b.customer_id = c.id
              AND (b.seller_id IS NULL OR b.seller_id = '')
              AND c.seller_id IS NOT NULL
              AND c.seller_id != ''
              AND u.first_name IS NOT NULL
          `);
          console.log(`✅ [SELLER-FIX] Vendedores corrigidos: ${(sellerFixResult as any).rowCount ?? 0} billings atualizados`);
        } catch (sellerFixErr: any) {
          console.log(`⚠️ [SELLER-FIX] Erro ao corrigir vendedores: ${sellerFixErr.message}`);
        }

        // 2. Enriquecimento de NFs por instância
        console.log(`\n🔍 [ENRICH-NF] Iniciando enriquecimento de NFs em background...`);
        for (const inst of activeInstances) {
          try {
            const enrichSvc = await getOmieServiceForInstance(storage, inst.id);
            if (enrichSvc) {
              // Loop até não haver mais NFs pendentes (máx 5 rodadas de 300 = 1500 por instância)
              let round = 0;
              const maxRounds = 5;
              while (round < maxRounds) {
                const enrichResult = await (enrichSvc as any).enrichMissingNfNumbers(300) as { enriched: number; checked: number };
                round++;
                console.log(`🔍 [ENRICH-NF] ${inst.name || inst.id} rodada ${round}: ${enrichResult.enriched}/${enrichResult.checked} enriquecidos`);
                if (enrichResult.checked === 0 || enrichResult.enriched === 0) break; // Nada mais pendente
                if (enrichResult.checked < 300) break; // Menos que batch = terminou
              }
            }
          } catch (enrichErr: any) {
            console.log(`⚠️ [ENRICH-NF] Erro na instância ${inst.name || inst.id}: ${enrichErr.message}`);
          }
        }
        console.log(`✅ [ENRICH-NF] Enriquecimento concluído para todas as instâncias.`);
      });

    } catch (error: any) {
      billingSyncState.status = 'error';
      billingSyncState.message = `Erro: ${error.message}`;
      await storage.updateSyncStatus('omie_billings', {
        status: 'error',
        message: `Erro na sincronização manual: ${error.message}`
      });
      console.error('Erro ao sincronizar faturamentos:', error);
    }
  });

