  // Check-in em um lead (com foto obrigatória)
  app.post('/api/leads/:id/check-in', upload.single('photo'), async (req: any, res) => {
    console.log(`🚀 [CHECK-IN] POST /api/leads/${req.params.id}/check-in`);
    console.log(`🚀 [CHECK-IN] Headers:`, req.headers);
    console.log(`🚀 [CHECK-IN] Session:`, !!req.session);
    
    try {
      // Autenticar manualmente dentro do handler
      let userId: string | null = null;
      let userEmail: string | null = null;
      
      if ((req.session as any)?.userId) {
        userId = (req.session as any).userId;
        userEmail = (req.session as any)?.userEmail;
        console.log(`✅ [CHECK-IN] Autenticado via session userId: ${userEmail}`);
      } else if ((req.session as any)?.user?.claims?.sub) {
        userId = (req.session as any).user.claims.sub;
        userEmail = (req.session as any).user.claims.email;
        console.log(`✅ [CHECK-IN] Autenticado via claims: ${userEmail}`);
      } else if (req.isAuthenticated && req.isAuthenticated() && (req.user as any)?.claims?.sub) {
        userId = (req.user as any).claims.sub;
        userEmail = (req.user as any).claims.email;
        console.log(`✅ [CHECK-IN] Autenticado via Passport: ${userEmail}`);
      }
      
      if (!userId) {
        console.log(`❌ [CHECK-IN] Não autenticado`);
        return res.status(401).json({ message: "Unauthorized" });
      }
      
      // Buscar usuário
      let user = await storage.getUser(userId);
      if (!user && userEmail) {
        user = await storage.getUserByEmail(userEmail);
      }
      
      if (!user || !user.isActive) {
        console.log(`❌ [CHECK-IN] User not found or inactive`);
        return res.status(401).json({ message: "User not found or inactive" });
      }
      
      const { id } = req.params;
      const { latitude, longitude } = req.body;
      
      console.log(`📍 Check-in em lead ${id} - User: ${user?.email || 'UNKNOWN'}, File: ${req.file ? 'Sim' : 'Não'}, Coords: (${latitude}, ${longitude})`);
      
      // Foto é obrigatória para check-in em lead
      if (!req.file) {
        console.log(`❌ Foto não enviada`);
        return res.status(400).json({
          message: 'Foto é obrigatória para check-in em lead',
          isLead: true,
          requiresPhoto: true
        });
      }
      
      // Validar latitude/longitude
      if (!latitude || !longitude) {
        console.log(`❌ Coords inválidas: ${latitude}, ${longitude}`);
        return res.status(400).json({ 
          message: 'Latitude e longitude são obrigatórias' 
        });
      }
      
      // Buscar lead
      const lead = await storage.getLead(id);
      if (!lead) {
        console.log(`❌ Lead ${id} não encontrado na tabela leads`);
        return res.status(404).json({ 
          message: 'Lead não encontrado. Este registro pode ter sido removido ou não é um lead válido.',
          leadId: id
        });
      }
      
      console.log(`✅ Lead encontrado: ${lead.fantasyName}, assignedTo: ${lead.assignedTo}, user.id: ${user.id}`);
      
      // Apenas o vendedor atribuído ou admin pode fazer check-in
      if (user.role === 'vendedor' && lead.assignedTo !== user.id) {
        console.log(`❌ Acesso negado - não é o vendedor atribuído`);
        return res.status(403).json({ 
          message: 'Você não está atribuído a este lead' 
        });
      }
      
      // Calcular distância até o lead usando Haversine
      let checkInDistance = null;
      const leadLat = parseFloat(lead.latitude.toString());
      const leadLon = parseFloat(lead.longitude.toString());
      const userLat = parseFloat(latitude);
      const userLon = parseFloat(longitude);
      
      const R = 6371000; // Raio da Terra em metros
      const dLat = (leadLat - userLat) * Math.PI / 180;
      const dLon = (leadLon - userLon) * Math.PI / 180;
      const a = 
        Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(userLat * Math.PI / 180) * Math.cos(leadLat * Math.PI / 180) * 
        Math.sin(dLon/2) * Math.sin(dLon/2);
      const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
      checkInDistance = R * c;
      
      // Converter foto para base64
      const base64Photo = req.file.buffer.toString('base64');
      const photoUrl = `data:${req.file.mimetype};base64,${base64Photo}`;
      
      // Atualizar lead com check-in usando db.update direto (bypassa insertLeadSchema validation)
      const now = nowBrazil();
      try {
        console.log(`🔄 Atualizando lead ${id} no banco de dados...`);
        await db
          .update(leads)
          .set({
            lastCheckInAt: now,
            status: 'visited', // Marcar como visitado
            photo: photoUrl, // Salvar foto no lead
            updatedAt: now
          })
          .where(eq(leads.id, id))
          .execute();
        
        console.log(`✅ Lead atualizado no banco de dados`);
        
        // Registrar checkpoint na rota diária (para aparecer na listagem)
        let routeProgress = null;
        try {
          const sellerId = lead.assignedTo || user.id;
          // Usar timezone do Brasil para garantir que encontramos a rota correta
          const todayBrazil = todayBrazilMidnight();
          const dailyRoute = await storage.getDailyRouteBySellerAndDate(sellerId, todayBrazil);
          
          if (dailyRoute) {
            // Buscar o visitId correspondente ao lead na rota
            const visits = dailyRoute.visits || [];
            const leadVisit = visits.find((v: any) => 
              v.visitType === 'lead' && (v.entityId === id || v.leadId === id || v.customerId === id)
            );
            
            if (leadVisit) {
              console.log(`📍 Registrando checkpoint de check-in para lead ${id} na rota ${dailyRoute.id}, visitId: ${leadVisit.id}`);
              const { registerCheckpoint } = await import('./routeOptimizationService');
              routeProgress = await registerCheckpoint(
                storage,
                dailyRoute.id,
                leadVisit.id,  // visitId da rota
                id,            // customerId = lead ID
                sellerId,
                'check_in',
                userLat,
                userLon,
                photoUrl       // Passar URL da foto
              );
              console.log(`✅ Checkpoint de check-in registrado para lead`);
            } else {
              console.log(`⚠️ Lead ${id} não encontrado na rota diária do vendedor`);
            }
          } else {
            console.log(`⚠️ Nenhuma rota diária encontrada para o vendedor ${sellerId}`);
          }
        } catch (checkpointError: any) {
          console.error('❌ Erro ao registrar checkpoint de check-in:', checkpointError);
          // Não falhar o check-in se checkpoint falhar
        }
        
        console.log(`✅ Check-in realizado em lead ${lead.fantasyName} - Distância: ${Math.round(checkInDistance)}m, Foto salva`);
        
        res.json({
          message: 'Check-in realizado com sucesso',
          lead: {
            id: lead.id,
            fantasyName: lead.fantasyName,
            lastCheckInAt: now,
            status: 'visited',
            checkInDistance: Math.round(checkInDistance),
            photoUrl: photoUrl
          },
          routeProgress
        });
      } catch (dbError) {
        console.error('❌ Erro ao atualizar lead no banco de dados:', dbError);
        throw dbError;
      }
    } catch (error) {
      console.error('❌ Erro ao fazer check-in em lead:', error);
      console.error('❌ Stack completo:', (error as any)?.stack);
      const errorMsg = (error as any)?.message || 'Erro desconhecido';
      console.error('❌ Detalhes:', { errorMsg, errorName: (error as any)?.name });
      res.status(500).json({ message: 'Erro ao fazer check-in em lead', details: errorMsg });
    }
  });
  
  // Check-out em um lead
  app.post('/api/leads/:id/check-out', authenticateUser, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { latitude, longitude } = req.body;
      const user = req.currentUser;
      
      // Validar latitude/longitude
      if (!latitude || !longitude) {
        return res.status(400).json({ 
          message: 'Latitude e longitude são obrigatórias' 
        });
      }
      
      // Buscar lead
      const lead = await storage.getLead(id);
      if (!lead) {
        return res.status(404).json({ message: 'Lead não encontrado' });
      }
      
      // Apenas o vendedor atribuído ou admin pode fazer check-out
      if (user.role === 'vendedor' && lead.assignedTo !== user.id) {
        return res.status(403).json({ 
          message: 'Você não está atribuído a este lead' 
        });
      }
      
      // Validar que houve check-in antes
      if (!lead.lastCheckInAt) {
        return res.status(400).json({
          message: 'Lead não tem check-in registrado'
        });
      }
      
      // Atualizar lead com check-out usando db.update direto (bypassa insertLeadSchema validation)
      const now = nowBrazil();
      try {
        await db
          .update(leads)
          .set({
            lastCheckOutAt: now,
            status: 'visited', // Manter como visitado (valor válido no enum)
            updatedAt: now
          })
          .where(eq(leads.id, id));
        
        console.log(`✅ Lead atualizado com check-out`);
        
        // Registrar checkpoint de check-out na rota diária
        let routeProgress = null;
        try {
          const sellerId = lead.assignedTo || user.id;
          // Usar timezone do Brasil para garantir que encontramos a rota correta
          const todayBrazil = todayBrazilMidnight();
          const dailyRoute = await storage.getDailyRouteBySellerAndDate(sellerId, todayBrazil);
          
          if (dailyRoute) {
            const visits = dailyRoute.visits || [];
            const leadVisit = visits.find((v: any) => 
              v.visitType === 'lead' && (v.entityId === id || v.leadId === id || v.customerId === id)
            );
            
            if (leadVisit) {
              console.log(`📍 Registrando checkpoint de check-out para lead ${id} na rota ${dailyRoute.id}`);
              const { registerCheckpoint } = await import('./routeOptimizationService');
              routeProgress = await registerCheckpoint(
                storage,
                dailyRoute.id,
                leadVisit.id,
                id,
                sellerId,
                'check_out',
                parseFloat(latitude),
                parseFloat(longitude)
              );
              console.log(`✅ Checkpoint de check-out registrado para lead`);
            }
          }
        } catch (checkpointError: any) {
          console.error('❌ Erro ao registrar checkpoint de check-out:', checkpointError);
        }
        
        console.log(`✅ Check-out realizado em lead ${lead.fantasyName}`);
        
        res.json({
          message: 'Check-out realizado com sucesso',
          lead: {
            id: lead.id,
            fantasyName: lead.fantasyName,
            lastCheckInAt: lead.lastCheckInAt,
            lastCheckOutAt: now,
            status: 'visited'
          },
          routeProgress
        });
      } catch (dbError) {
        console.error('Erro ao atualizar lead no banco de dados:', dbError);
        throw dbError;
      }
    } catch (error) {
      console.error('Erro ao fazer check-out em lead:', error);
      res.status(500).json({ message: 'Erro ao fazer check-out em lead', error: (error as any).message });
    }
  });

